const BFF_G1: BirthdaySubGroup = {
  id: 'bff_g1',
  title: 'On se connaît depuis trop longtemps',
  messages: [
    { id: 'bff_g1_01', text: `"Joyeux anniversaire. On se connaît depuis combien de temps exactement." J'ai calculé. C'est beaucoup. C'est suffisamment longtemps pour avoir traversé plusieurs versions de nous deux. Plusieurs coiffures. Plusieurs appartements. Plusieurs crises. Plusieurs bonheurs. Plusieurs trucs dont on parle encore et d'autres dont on ne parle plus jamais. Joyeux anniversaire, {prenom}, vieille histoire.\nAvec calcul précis du nombre d'années et respect pour ce que ça représente, — Quelqu'un qui était là avant que tu sois vraiment toi et le sera après 📅` },
    { id: 'bff_g1_02', text: `"Joyeux anniversaire. Tu peux plus me mentir." Pas sur les vraies choses. T'essaies parfois. Je vois. Ton visage fait quelque chose. Ta voix change légèrement. Il y a un micro-décalage entre ce que tu dis et ce que tu penses. Je dis rien. Mais je vois. Depuis le temps je vois tout. Joyeux anniversaire, {prenom}.\nAvec détecteur de mensonge calibré sur ta fréquence spécifique depuis des années, — Quelqu'un qui sait et attend que tu le dises toi-même quand tu seras prêt 🔍` },
    { id: 'bff_g1_03', text: `"Joyeux anniversaire. J'ai connu ta pire période." Pas la plus facile à raconter. Pas celle que tu mets en avant. L'autre. Celle où tu étais moins bien. Moins toi. Moins sûr. Et j'étais là. Et j'ai vu. Et je suis toujours là. Et je t'aime autant maintenant qu'à ce moment-là. Joyeux anniversaire, {prenom}.\nAvec mémoire complète de toutes les périodes et présence dans chacune, — Quelqu'un qui te connaît dans toutes tes versions et reste 💛` },
    { id: 'bff_g1_04', text: `"Joyeux anniversaire. On a survécu à des trucs qui auraient dû nous séparer." Des malentendus. Des distances. Des périodes de silence. Des moments où l'un de nous était pas disponible pour l'autre. Des moments difficiles qui auraient pu tout abîmer. Et ça a tenu. Pas par hasard. Par choix. Joyeux anniversaire, {prenom}.\nAvec respect pour la résistance de ce lien face à tout ce qui aurait pu le casser, — Quelqu'un qui a choisi de rester à chaque carrefour et referait ce choix 🛤️` },
    { id: 'bff_g1_05', text: `"Joyeux anniversaire. Je t'ai vu avant que tu sois présentable." Physiquement. Émotionnellement. T'as pas fait d'efforts pour m'impressionner. T'étais juste toi. Avec le désordre et les doutes et les mauvais jours et les bonnes idées mélangés. Et c'est cette version-là que j'ai choisie. Joyeux anniversaire, {prenom}.\nAvec référence à des moments spécifiques où tu étais clairement pas à ton meilleur, — Quelqu'un qui t'a vu sans préparation et est quand même resté 🪞` },
    { id: 'bff_g1_06', text: `"Joyeux anniversaire. Je sais comment tu étais à vingt ans." En détail. Avec les preuves. Les photos existent. Les anecdotes existent. Les témoignages existent. Je suis une archive vivante de qui tu étais avant que tu deviennes qui tu es. C'est un pouvoir que je n'utilise qu'avec modération. Joyeux anniversaire, {prenom}.\nAvec archives complètes accessibles sur demande ou en cas de nécessité diplomatique, — Quelqu'un qui garde les preuves au chaud mais les utilise rarement 📁` },
    { id: 'bff_g1_07', text: `"Joyeux anniversaire. T'as changé et je t'aime autant." Pas pareil qu'avant. Différent. Sur des points importants. Certains changements je les avais vus venir. D'autres m'ont surpris. Dans le bon sens. T'es devenu quelqu'un que j'aurais peut-être pas prévu mais que je préfère probablement. Joyeux anniversaire, {prenom}.\nAvec bilan des changements observés et verdict globalement très positif, — Quelqu'un qui a suivi toute l'évolution et approuve la direction générale 📈` },
    { id: 'bff_g1_08', text: `"Joyeux anniversaire. Je me souviens exactement comment on s'est rencontrés." T'en souviens-tu de la même façon. Probablement pas. On a chacun notre version. La mienne est précise. Elle a des détails que t'as peut-être oubliés. Ce premier moment où quelque chose a dit que ça allait durer. Joyeux anniversaire, {prenom}.\nAvec version personnelle du moment fondateur conservée intacte, — Quelqu'un qui se souvient du début et qui pense que c'était bien de commencer 🌱` },
    { id: 'bff_g1_09', text: `"Joyeux anniversaire. On a des opinions l'un sur l'autre que les autres ont pas." Des vraies. Des fondées sur des preuves réelles. Des années d'observation directe. Personne autour de toi te connaît comme je te connais. C'est une responsabilité. Je la prends au sérieux. Joyeux anniversaire, {prenom}.\nAvec conscience de ce que cette connaissance représente et du soin qu'elle demande, — Quelqu'un qui utilise cette connaissance pour ton bien presque toujours 🧠` },
    { id: 'bff_g1_10', text: `"Joyeux anniversaire. On a eu des désaccords sérieux." Pas des broutilles. Des vrais. Sur des sujets importants. Où on avait tort et raison différemment. Où on s'est dit des choses difficiles. Et on a tenu quand même. Parce que le lien était plus fort que les désaccords. Joyeux anniversaire, {prenom}.\nAvec respect pour ce que traverser des désaccords sérieux ensemble représente, — Quelqu'un qui a eu tort dans certains de ces désaccords et préfère pas dire lesquels 🤝` },
    { id: 'bff_g1_11', text: `"Joyeux anniversaire. Je sais ce qui te ferait vraiment plaisir." Pas ce que tu demandes. Ce qui te ferait vraiment plaisir. Ces deux choses ne sont pas toujours les mêmes. T'as des besoins que tu n'exprimes pas. Des envies que tu ne formules pas. Je les connais. Depuis le temps. Joyeux anniversaire, {prenom}.\nAvec connaissance de tes vrais besoins et effort pour y répondre même sans demande, — Quelqu'un qui essaie d'anticiper depuis des années et réussit parfois 🎯` },
    { id: 'bff_g1_12', text: `"Joyeux anniversaire. T'as été là pour moi d'une façon que je peux pas oublier." Il y a eu des moments. Précis. Où t'aurais pu pas être là. Où c'était compliqué pour toi aussi. Où t'as quand même choisi d'être présent. Ces moments-là je les porte. Ils font partie de pourquoi je suis là ce soir. Joyeux anniversaire, {prenom}.\nAvec reconnaissance pour des moments spécifiques gardés précieusement, — Quelqu'un qui n'oublie pas ce genre de chose et compte bien le rendre 💛` },
    { id: 'bff_g1_13', text: `"Joyeux anniversaire. On a un langage qu'on est les seuls à parler." Des références. Des raccourcis. Des mots qui veulent dire quelque chose de précis pour nous et rien pour les autres. Ce vocabulaire commun construit sur des années d'histoires partagées. Ce langage privé. Joyeux anniversaire, {prenom}.\nAvec gratitude pour ce langage et tout ce qu'il a fallu vivre pour le construire, — Quelqu'un qui parle couramment cette langue et apprécie d'être bilingue avec toi 🗣️` },
    { id: 'bff_g1_14', text: `"Joyeux anniversaire. On se connaît depuis assez longtemps pour se dire les vraies choses." Pas toujours agréables. Mais vraies. Ce niveau de confiance où on peut dire quelque chose de difficile parce qu'on sait comment ça sera reçu. Parce qu'on sait que ça vient d'un bon endroit. Parce que l'amitié est assez solide pour supporter la vérité. Joyeux anniversaire, {prenom}.\nAvec gratitude pour cette solidité qui permet la franchise, — Quelqu'un qui t'a dit des vérités difficiles et vice versa et qui trouve ça précieux 💎` },
    { id: 'bff_g1_15', text: `"Joyeux anniversaire. Je me souviens de la première fois que t'as parlé de quelque chose d'important." Ce sujet. Cette conversation. Ce moment où t'avais décidé de me faire confiance sur quelque chose de vrai. Je me souviens de l'endroit. De l'heure approximativement. De ce que j'ai ressenti. C'était un tournant. Joyeux anniversaire, {prenom}.\nAvec mémoire précise du moment de confiance fondateur et de ce qu'il a représenté, — Quelqu'un qui a compris ce que ce moment signifiait et l'a traité avec soin 🤍` },
    { id: 'bff_g1_16', text: `"Joyeux anniversaire. On a passé des heures à ne rien faire ensemble." Pas seulement des moments forts. Des heures ordinaires. Assis quelque part. Pas obligés de se divertir. Pas obligés de se parler tout le temps. Ces heures de présence silencieuse et confortable. Joyeux anniversaire, {prenom}.\nAvec nostalgie pour ces heures et gratitude pour leur existence dans notre histoire, — Quelqu'un avec qui le silence est confortable depuis longtemps 🛋️` },
    { id: 'bff_g1_17', text: `"Joyeux anniversaire. T'as été témoin de ma vie aussi." C'est réciproque. Je t'ai vu. Tu m'as vu. On est les témoins l'un de l'autre. Cette fonction rare. Être là quand quelque chose se passe. Être la personne qui peut dire j'étais là. Joyeux anniversaire, {prenom}, mon témoin.\nAvec reconnaissance de ce rôle mutuel et de sa valeur unique, — Quelqu'un qui est content que tu aies été là pour voir aussi 👀` },
    { id: 'bff_g1_18', text: `"Joyeux anniversaire. On a ri de choses qu'on peut raconter à personne." Ces fous rires. Ces situations. Ces moments qu'on a partagés et qui n'appartiennent qu'à nous. Pas par honte. Par intimité. Parce que certaines choses n'existent que dans le contexte de ce qu'on est l'un pour l'autre. Joyeux anniversaire, {prenom}.\nAvec pensée pour au moins trois de ces moments précis ce soir, — Quelqu'un qui rit encore en y pensant et sait exactement lesquels tu penses aussi 😂` },
    { id: 'bff_g1_19', text: `"Joyeux anniversaire. Je t'aurais choisi si on s'était pas rencontrés par hasard." Si on m'avait décrit quelqu'un. Avec tes qualités. Tes défauts. Ta façon d'être. Et qu'on m'avait demandé si je voulais cette personne dans ma vie. J'aurais dit oui. Pas parce que t'es parfait. Parce que t'es exactement le type de personne dont j'ai besoin. Joyeux anniversaire, {prenom}.\nAvec certitude que ce n'était pas que du hasard et que le choix aurait été le même, — Quelqu'un qui te choisit activement et pas juste par inertie depuis longtemps 🎯` },
    { id: 'bff_g1_20', text: `"Joyeux anniversaire. On se connaît depuis trop longtemps pour que je t'offre autre chose que la vérité." Les beaux discours je pourrais. Les compliments polis aussi. Mais t'as pas besoin de ça de ma part. T'as besoin de quelqu'un qui te connaît vraiment et qui est là vraiment. Voilà ce que je suis. Voilà ce que je t'offre ce soir. Joyeux anniversaire, {prenom}.\nAvec honnêteté comme cadeau principal et présence comme cadeau secondaire, — Quelqu'un qui est là ce soir et le sera demain et c'est tout ce qu'il y a à dire ❤️` },
  ],
};

const BFF_G2: BirthdaySubGroup = {
  id: 'bff_g2',
  title: 'Les souvenirs qu\'on est les seuls à avoir',
  messages: [
    { id: 'bff_g2_01', text: `"Joyeux anniversaire. Il y a des choses qui n'existent que pour nous deux." Pas dans des photos. Pas dans des stories. Pas racontées à d'autres. Des moments qui vivent uniquement dans nos deux mémoires. Qui disparaîtront si l'un de nous oublie. Ces moments-là sont les plus précieux parce qu'ils n'appartiennent qu'à nous. Joyeux anniversaire, {prenom}.\nAvec pensée pour tous ces moments non documentés et leur valeur spécifique, — Quelqu'un qui les garde soigneusement et les sortira aux bons moments 🤫` },
    { id: 'bff_g2_02', text: `"Joyeux anniversaire. Cette nuit où on s'est retrouvés dans une situation inexplicable." T'en souviens-tu. La série d'événements qui avait mené là. L'heure improbable. Le contexte absurde. Comment on était arrivés là. Comment on en était sortis. Et ce qu'on avait dit dans la voiture ou en marchant après. Ce souvenir qui résiste à toute tentative d'explication rationnelle. Joyeux anniversaire, {prenom}.\nAvec version personnelle de cette nuit conservée intacte dans ses moindres détails, — Quelqu'un qui y repense encore régulièrement et sourit à chaque fois 🌙` },
    { id: 'bff_g2_03', text: `"Joyeux anniversaire. Cette fois où tu m'as appelé à une heure impossible." L'heure. Le sujet. L'urgence réelle ou perçue. Ce que j'ai répondu. Ce qu'on s'est dit. Comment ça s'était terminé. Ces appels-là qui ont une place à part dans l'histoire de ce qu'on est l'un pour l'autre. Joyeux anniversaire, {prenom}.\nAvec mémoire précise de l'heure et du sujet et de ma réaction de l'époque, — Quelqu'un qui a répondu et recommencerait sans hésiter 📞` },
    { id: 'bff_g2_04', text: `"Joyeux anniversaire. Ce voyage où rien s'était passé comme prévu." Le plan de départ. Ce qui avait changé en premier. Ce qui avait changé ensuite. Le moment où on avait arrêté de suivre le plan et commencé à juste voir. Ce que ça avait donné. Ce souvenir qui est meilleur précisément parce que rien s'était passé comme prévu. Joyeux anniversaire, {prenom}.\nAvec gratitude pour tous les plans qui foire et donnent les meilleurs souvenirs, — Quelqu'un qui referait ce voyage exactement comme ça si c'était possible ✈️` },
    { id: 'bff_g2_05', text: `"Joyeux anniversaire. Cette conversation qui avait duré toute la nuit." Le sujet de départ. Comment on avait dérivé. Où on avait fini. Ce qu'on s'était dit qu'on avait jamais dit avant. Ce qu'on avait compris cette nuit-là. Ces conversations nocturnes qui reconfigurent quelque chose. Joyeux anniversaire, {prenom}.\nAvec pensée pour ce qui avait été dit et pour ce que ça avait changé après, — Quelqu'un qui se souvient de chaque virage de cette conversation 🌅` },
    { id: 'bff_g2_06', text: `"Joyeux anniversaire. Cette période difficile qu'on a traversée ensemble." Pas facile à raconter maintenant. Pas glamour. Pas le genre de souvenir qu'on met en avant. Mais c'est ce genre de période qui dit quelque chose de réel sur ce qu'une amitié peut porter. On l'a portée. On est là. Joyeux anniversaire, {prenom}.\nAvec respect pour ce que cette période a coûté et pour ce qu'elle a prouvé, — Quelqu'un qui était là pendant et qui n'a pas trouvé ça difficile de rester 💪` },
    { id: 'bff_g2_07', text: `"Joyeux anniversaire. Ce fou rire qu'on peut pas expliquer." Le déclencheur était rien. Ou quelque chose de si spécifique au contexte qu'il faudrait tout réexpliquer. Et même en expliquant tout les autres comprennent pas vraiment. Ce fou rire qui n'appartient qu'au moment où il s'est passé. Joyeux anniversaire, {prenom}.\nAvec sourire immédiat rien qu'à y penser et certitude que toi aussi, — Quelqu'un qui rit encore en y repensant maintenant même 😂` },
    { id: 'bff_g2_08', text: `"Joyeux anniversaire. Cette décision qu'on a prise ensemble et qu'on avait dit à personne." Le contexte. La décision. Pourquoi on en avait pas parlé. Ce que ça avait donné. Ces décisions collectives secrètes qui font partie du tissu de ce qu'on est ensemble. Joyeux anniversaire, {prenom}.\nAvec mémoire précise de cette décision et de ses conséquences, — Quelqu'un qui a gardé le secret et continuera de le garder aussi longtemps que nécessaire 🤐` },
    { id: 'bff_g2_09', text: `"Joyeux anniversaire. Cette période où on se voyait tous les jours." La géographie le permettait. Ou les circonstances. Et on en avait profité sans savoir que ça allait changer. Ces périodes d'intensité quotidienne qui créent un type de lien particulier. Joyeux anniversaire, {prenom}.\nAvec nostalgie pour cette période et gratitude pour ce qu'elle a construit, — Quelqu'un qui repense parfois à cette époque avec quelque chose de doux 🏠` },
    { id: 'bff_g2_10', text: `"Joyeux anniversaire. Ce moment où t'as fait quelque chose de courageux et je suis le seul à le savoir." Les autres ont pas vu. Ou ont pas compris ce que c'était vraiment. Moi oui. Je savais ce que ça te coûtait. Je savais ce qu'il avait fallu pour faire ça. Et tu l'as fait quand même. Joyeux anniversaire, {prenom}, courageux en secret.\nAvec témoignage silencieux de ce courage et respect qui n'a jamais été dit assez fort, — Quelqu'un qui t'a vu faire ça et en est fier encore aujourd'hui 🦁` },
    { id: 'bff_g2_11', text: `"Joyeux anniversaire. Ce souvenir qu'on raconte différemment." On y était tous les deux. Et nos versions divergent sur des points importants. Pas par mauvaise foi. Par mémoire. Par angle. Par ce qu'on avait choisi de retenir. Ces souvenirs partagés mais différents qui disent quelque chose sur comment on perçoit les mêmes choses. Joyeux anniversaire, {prenom}.\nAvec curiosité persistante pour la version de l'autre et débat maintenu en suspens, — Quelqu'un dont la version est probablement moins précise que la mienne 😄` },
    { id: 'bff_g2_12', text: `"Joyeux anniversaire. Ce jour ordinaire dont je me souviens sans raison particulière." Pas un événement. Pas une crise. Pas une célébration. Un jour normal. Quelque chose qu'on faisait. Un trajet. Une conversation banale. Un moment si ordinaire qu'il n'y avait aucune raison de le retenir. Et je l'ai retenu. Joyeux anniversaire, {prenom}.\nAvec gratitude pour les jours ordinaires qui font le fond de ce qu'on est ensemble, — Quelqu'un qui se souvient de jours dont tu n'as probablement aucun souvenir 📆` },
    { id: 'bff_g2_13', text: `"Joyeux anniversaire. Cette chose que t'as faite pour moi que j'ai jamais vraiment remerciée." Il y en a une. Spécifique. Que tu te souviens peut-être pas avoir faite. Ou que tu considères comme normale. Et qui ne l'était pas. Qui comptait vraiment. Et dont je t'ai jamais vraiment remercié. Joyeux anniversaire, {prenom}, merci pour ça.\nAvec merci tardif mais sincère pour quelque chose de précis et réel, — Quelqu'un qui a gardé ça et choisit aujourd'hui pour le dire 🙏` },
    { id: 'bff_g2_14', text: `"Joyeux anniversaire. Ce moment où j'ai compris qu'on serait amis longtemps." Il y a eu un instant précis. Pas forcément mémorable en surface. Mais quelque chose avait dit que ça allait durer. Que c'était différent d'une connaissance. Que c'était quelque chose d'autre. Je me souviens de cet instant. Joyeux anniversaire, {prenom}.\nAvec mémoire précise de ce moment charnière et gratitude pour ce qu'il annonçait, — Quelqu'un qui avait raison ce jour-là sur ce que ça allait être 🌟` },
    { id: 'bff_g2_15', text: `"Joyeux anniversaire. Cette période où on était séparés par la distance." La géographie avait mis quelque chose entre nous. Et ça avait tenu quand même. Pas facilement toujours. Mais ça avait tenu. Et quand la distance avait disparu on avait repris là où on s'était arrêtés. Joyeux anniversaire, {prenom}.\nAvec respect pour ce que ça avait demandé de maintenir quelque chose à distance, — Quelqu'un qui avait compté les retrouvailles et trouvé chaque fois que ça valait l'attente ✈️` },
    { id: 'bff_g2_16', text: `"Joyeux anniversaire. Ce truc qu'on a fait et qu'on dirait jamais à nos parents." Ou à certaines personnes. Pas parce que c'était mal. Parce que c'était à nous. Parce que certaines choses appartiennent à une période et à une complicité et n'ont pas besoin d'être partagées plus loin. Joyeux anniversaire, {prenom}.\nAvec sourire immédiat à la pensée de ce truc précis, — Quelqu'un qui sait exactement de quoi on parle et confirme que ça reste entre nous 😏` },
    { id: 'bff_g2_17', text: `"Joyeux anniversaire. Cette nuit où on avait attendu ensemble sans savoir comment ça allait finir." L'attente. L'incertitude. Ce qu'on s'était dit pendant. Ce qu'on n'avait pas dit. Comment on avait occupé le temps. Ce que ça avait donné. Ces attentes partagées qui créent un lien particulier. Joyeux anniversaire, {prenom}.\nAvec pensée pour tout ce qui avait été ressenti pendant cette attente, — Quelqu'un qui était content de ne pas attendre seul et qui le dit maintenant 🌑` },
    { id: 'bff_g2_18', text: `"Joyeux anniversaire. Ces photos de nous que j'ai et que t'as probablement oubliées." Elles existent. Sur un disque dur quelque part. Sur un téléphone ancien. Dans une boîte physique peut-être. Ces images de nous à des moments qu'on reconnaîtrait à peine. Ces preuves visuelles de tout ce temps passé. Joyeux anniversaire, {prenom}.\nAvec promesse de les ressortir un jour au moment le plus opportun ou inopportun, — Quelqu'un qui a les archives et sait s'en servir avec discernement 📷` },
    { id: 'bff_g2_19', text: `"Joyeux anniversaire. Cette chose que t'as dite un jour et qui m'a changé." T'en souviens-tu. Probablement pas. Une phrase. Un conseil. Une observation. Dite peut-être en passant. Qui a atterri d'une façon que tu n'avais pas prévue. Qui a changé quelque chose dans ma façon de voir. Joyeux anniversaire, {prenom}, tu sais pas l'effet que tu as.\nAvec gratitude pour des mots dont tu ignorais probablement la portée, — Quelqu'un que tu as changé sans le savoir et qui t'en est reconnaissant 🌱` },
    { id: 'bff_g2_20', text: `"Joyeux anniversaire. Tout ce qu'on a vécu ensemble fait partie de qui je suis." Pas métaphoriquement. Concrètement. Des choses que je pense viennent de conversations avec toi. Des façons que j'ai de voir viennent de ce qu'on a traversé ensemble. Tu fais partie de ma construction. Joyeux anniversaire, {prenom}.\nAvec conscience de ce que cette présence dans ma construction représente, — Quelqu'un qui est en partie qui il est grâce à toi et le dit aujourd'hui ❤️` },
  ],
};

const BFF_G3: BirthdaySubGroup = {
  id: 'bff_g3',
  title: 'Ce que tu fais pour moi que personne d\'autre ferait',
  messages: [
    { id: 'bff_g3_01', text: `"Joyeux anniversaire. T'es le seul ou la seule qui répond à mes messages de 2h du matin." Pas toujours immédiatement. Mais tu réponds. T'as jamais dit c'est trop tard ou c'est trop bizarre ou envoie un message normal à une heure normale. Tu réponds. Avec la même attention qu'à n'importe quelle heure. Joyeux anniversaire, {prenom}.\nAvec gratitude pour chaque réponse nocturne reçue au fil des années, — Quelqu'un qui sait que tu es là même à 2h et que ça compte énormément 🌙` },
    { id: 'bff_g3_02', text: `"Joyeux anniversaire. Tu me dis la vérité même quand c'est inconfortable." Pas tout le monde fait ça. La plupart préfèrent l'ambiguïté bienveillante. Le peut-être que si. Le c'est pas si mal. Toi tu me dis ce que tu penses vraiment. Avec tact. Mais vraiment. C'est précieux et rare et je le sais. Joyeux anniversaire, {prenom}.\nAvec gratitude pour les vérités inconfortables dites au bon moment, — Quelqu'un qui t'en a voulu sur le coup et t'en est reconnaissant après 💎` },
    { id: 'bff_g3_03', text: `"Joyeux anniversaire. Tu retiens les détails de ma vie." Les noms. Les situations. Les trucs que j'ai mentionnés en passant. Tu t'en souviens. Tu demandes des nouvelles de quelque chose que j'avais dit il y a trois semaines. Cette façon de montrer que t'as écouté. Que ce que je vis t'intéresse vraiment. Joyeux anniversaire, {prenom}.\nAvec émotion chaque fois que tu demandes des nouvelles de quelque chose que j'avais oublié avoir mentionné, — Quelqu'un qui se sent vu grâce à toi et l'apprécie plus qu'il ne le dit 👂` },
    { id: 'bff_g3_04', text: `"Joyeux anniversaire. Tu ris à mes blagues même les mauvaises." Surtout les mauvaises peut-être. Avec une générosité qui dit que c'est pas la blague qui compte c'est ce qu'elle représente. Ce rire accordé. Ce soutien comique inconditionnel. Cette façon de me laisser être drôle même quand je le suis pas vraiment. Joyeux anniversaire, {prenom}.\nAvec conscience que certaines de mes blagues ne méritaient vraiment pas le rire reçu, — Quelqu'un qui bénéficie de ton soutien comique et en abuse parfois 😄` },
    { id: 'bff_g3_05', text: `"Joyeux anniversaire. Tu viens quand j'appelle même si c'est pas pratique." Pas toujours facile pour toi. Pas toujours au bon moment. Mais tu viens. Tu trouves comment. T'arranges le reste. Et t'arrives. Cette disponibilité réelle derrière la disponibilité annoncée. Joyeux anniversaire, {prenom}.\nAvec mémoire précise des fois où c'était vraiment pas pratique et où tu es venu quand même, — Quelqu'un qui sait la différence entre les gens qui disent qu'ils viendraient et toi 🚗` },
    { id: 'bff_g3_06', text: `"Joyeux anniversaire. Tu gardes mes secrets sans que j'aie besoin de te le demander." Je t'ai jamais dit garde ça pour toi. T'as compris. Tu sais ce qui se partage et ce qui ne se partage pas. Tu gères ça avec une intelligence du contexte que tout le monde n'a pas. Joyeux anniversaire, {prenom}.\nAvec gratitude pour chaque secret gardé sans instructions explicites, — Quelqu'un qui sait qu'il peut tout dire et que ça reste là où ça doit rester 🤐` },
    { id: 'bff_g3_07', text: `"Joyeux anniversaire. Tu me rappelles qui je suis quand je m'égare." Pas de façon dramatique. Une phrase. Une observation. Un rappel discret de quelque chose que j'avais dit ou pensé avant. Cette façon de me ramener à moi-même quand je m'éloigne. Joyeux anniversaire, {prenom}, mon ancre.\nAvec reconnaissance pour chaque rappel qui m'a remis dans le bon sens, — Quelqu'un qui en a eu besoin plusieurs fois et sait que tu seras là pour les prochaines ⚓` },
    { id: 'bff_g3_08', text: `"Joyeux anniversaire. Tu t'intéresses à des trucs que tu trouves ennuyeux parce qu'ils m'intéressent." T'as pas choisi ce sujet. Il t'aurait jamais attiré seul. Mais parce que c'est important pour moi tu t'y es mis. Tu as appris des trucs. Tu poses des questions. Tu sembles presque convaincu parfois. Cette générosité intellectuelle. Joyeux anniversaire, {prenom}.\nAvec conscience que tu t'es ennuyé sur certains de mes sujets et gratitude pour l'effort, — Quelqu'un qui sait que tu fais semblant parfois et trouve ça très touchant quand même 🎭` },
    { id: 'bff_g3_09', text: `"Joyeux anniversaire. Tu fais semblant de pas remarquer quand je suis en mauvais état." Et tu remarques quand même. Je le sais. Mais tu choisis de pas le pointer du doigt. Tu laisses exister. Tu restes là. Tu attends que je sois prêt à en parler ou que ça passe. Cette façon de respecter mon rythme. Joyeux anniversaire, {prenom}.\nAvec gratitude pour cette retenue qui demande plus d'efforts que d'intervenir, — Quelqu'un qui apprécie que tu remarques et que tu attendes quand même 🤍` },
    { id: 'bff_g3_10', text: `"Joyeux anniversaire. Tu défends ma réputation quand je suis pas là." Je le sais pas toujours sur le moment. Mais ça remonte. Des gens me disent des trucs. Ou je comprends après coup. Que t'as dit quelque chose. Que t'as recadré quelque chose. Que t'as défendu quelque chose. En mon absence. Joyeux anniversaire, {prenom}.\nAvec gratitude pour ce que tu fais pour moi dans les conversations où je suis absent, — Quelqu'un qui sait que son image est entre de bonnes mains quand tu es là 🛡️` },
    { id: 'bff_g3_11', text: `"Joyeux anniversaire. Tu prends mon parti même quand t'as des doutes." T'es pas d'accord toujours. Je le sens parfois. Mais tu commences par être là. Par soutenir. Et les réserves tu me les dis après en privé. Pas devant les autres. Cette loyauté de façade publique avec honnêteté privée. C'est exactement le bon équilibre. Joyeux anniversaire, {prenom}.\nAvec respect pour cet équilibre parfait entre loyauté et honnêteté, — Quelqu'un qui sait que ton soutien public et tes réserves privées valent de l'or 🏅` },
    { id: 'bff_g3_12', text: `"Joyeux anniversaire. Tu réserves du temps pour moi sans que je demande." Tu penses à moi. Tu proposes. Tu prévois. T'attends pas que je sois en crise pour vérifier. Tu fais la maintenance de ce lien de ton côté aussi. Cette façon de prendre soin de notre amitié activement. Joyeux anniversaire, {prenom}.\nAvec conscience que les amitiés qui durent sont celles dont les deux côtés s'occupent, — Quelqu'un qui essaie de faire sa part et sait que tu fais la tienne 📅` },
    { id: 'bff_g3_13', text: `"Joyeux anniversaire. Tu t'adaptes à mon humeur sans me faire sentir coupable." Les jours où je suis moins bien. Moins disponible. Moins drôle. Moins là. Tu ajustes. T'exiges pas que je sois en forme. T'es là dans la version que j'ai ce jour-là. Joyeux anniversaire, {prenom}.\nAvec soulagement d'avoir quelqu'un qui accepte toutes les versions, — Quelqu'un qui apprécie de ne jamais avoir à performer pour toi 🌤️` },
    { id: 'bff_g3_14', text: `"Joyeux anniversaire. Tu te souviens des dates qui comptent pour moi." Pas seulement mon anniversaire. Les autres. Celles que j'ai mentionnées. Les rendez-vous importants. Les résultats attendus. Tu coches mentalement. Tu demandes après. Cette façon de suivre ma vie dans ses détails. Joyeux anniversaire, {prenom}.\nAvec émotion chaque fois que tu demandes des nouvelles d'une date que j'avais mentionnée, — Quelqu'un qui se sent suivi et compris grâce à toi 🗓️` },
    { id: 'bff_g3_15', text: `"Joyeux anniversaire. Tu trouves quoi dire quand je sais pas quoi faire." Pas forcément une solution. Parfois juste les bons mots. La bonne question. La perspective qui manquait. Ce talent de trouver quelque chose d'utile à dire dans les moments où les mots sont difficiles. Joyeux anniversaire, {prenom}.\nAvec gratitude pour chaque fois que tu as trouvé quoi dire quand je pensais qu'il n'y avait rien, — Quelqu'un qui t'a entendu trouver les mots plusieurs fois et s'en souvient 💬` },
    { id: 'bff_g3_16', text: `"Joyeux anniversaire. Tu ris de moi avec moi et jamais contre moi." Nuance importante. T'as de l'humour sur mes défauts. Sur mes situations. Sur mes ratages. Mais c'est toujours avec moi. Jamais aux dépens de. Jamais pour les autres. Toujours dans un espace où c'est safe. Joyeux anniversaire, {prenom}.\nAvec gratitude pour cette distinction fondamentale maintenue instinctivement, — Quelqu'un qui rit volontiers de lui-même avec toi et sait que c'est un privilège 😄` },
    { id: 'bff_g3_17', text: `"Joyeux anniversaire. Tu me donnes le bénéfice du doute par défaut." Quand quelque chose peut être interprété de deux façons tu prends la bonne. Pas naïvement. Avec connaissance de cause. Parce que tu me connais assez pour savoir que la bonne interprétation est probablement juste. Joyeux anniversaire, {prenom}.\nAvec reconnaissance pour ce bénéfice du doute systématique et mérité, — Quelqu'un qui apprécie de ne pas avoir à se justifier à chaque fois 🤝` },
    { id: 'bff_g3_18', text: `"Joyeux anniversaire. T'as aidé à déménager." Une fois. Peut-être plusieurs. Avec des cartons et des meubles et des escaliers et une pizza à la fin si t'avais de la chance. Ce type de service qui dit quelque chose sur la nature d'une amitié. Joyeux anniversaire, {prenom}, héros des déménagements.\nAvec gratitude éternelle pour les déménagements et conscience que ça se rembourse mal, — Quelqu'un qui sera là pour le prochain et espère sincèrement qu'il y en aura pas 📦` },
    { id: 'bff_g3_19', text: `"Joyeux anniversaire. Tu m'as supporté pendant mes phases." Les phases. Celle où j'étais dans quelque chose. Un sujet. Une idée. Une conviction. Un truc qui prenait beaucoup de place dans mes conversations pendant un moment. T'as écouté. T'as attendu que ça passe. T'as été là après. Joyeux anniversaire, {prenom}.\nAvec conscience que certaines phases ont duré plus longtemps que raisonnable, — Quelqu'un qui a traversé toutes tes phases aussi et propose un échange de gratitude 🌊` },
    { id: 'bff_g3_20', text: `"Joyeux anniversaire. Tu fais des choses pour moi que tu ferais pour personne d'autre." Je le sais. J'espère que tu le sais aussi. Que je vois ce que tu fais. Que je mesure ce que ça représente. Que je sais la différence entre ce que tu fais pour tout le monde et ce que tu fais pour moi spécifiquement. Joyeux anniversaire, {prenom}, je vois tout.\nAvec inventaire complet de tout ce qui est fait pour moi spécifiquement et de sa valeur, — Quelqu'un qui voit et qui n'oublie pas et qui est là ce soir pour dire merci ❤️` },
  ],
};

const BFF_G4: BirthdaySubGroup = {
  id: 'bff_g4',
  title: 'Nos codes et références internes',
  messages: [
    { id: 'bff_g4_01', text: `"Joyeux anniversaire. Il y a des choses qu'on dit qui veulent dire autre chose." Un mot. Une phrase. Une expression. Qui pour les autres veut dire ce qu'elle veut dire. Et pour nous veut dire quelque chose de complètement différent. Ce vocabulaire parallèle. Ce langage dans le langage. Joyeux anniversaire, {prenom}, co-auteur de notre dictionnaire.\nAvec pensée pour tous les mots qui ont un sens secret entre nous, — Quelqu'un qui parle couramment cette langue et apprécie d'être bilingue avec toi 📖` },
    { id: 'bff_g4_02', text: `"Joyeux anniversaire. On a des noms pour des gens que l'autre a jamais rencontrés." Des personnages. Des gens de ta vie ou de la mienne. Qu'on n'a pas forcément vus. Mais dont on a tellement parlé qu'ils existent dans notre vocabulaire commun. Avec leurs surnoms. Leurs caractéristiques. Leur rôle dans le récit. Joyeux anniversaire, {prenom}.\nAvec pensée pour tous ces personnages secondaires de nos récits respectifs, — Quelqu'un qui connaît des gens qu'il n'a jamais rencontrés grâce à toi 🎭` },
    { id: 'bff_g4_03', text: `"Joyeux anniversaire. On a une blague qui dure depuis des années." Elle vient d'où exactement. D'un moment. D'une phrase. D'une situation absurde. Et elle est restée. Elle revient. Dans des contextes différents. Elle vieillit pas. Elle est même meilleure avec le temps parce qu'elle porte tout ce qu'on a vécu depuis. Joyeux anniversaire, {prenom}.\nAvec sourire immédiat à la pensée de cette blague précise, — Quelqu'un qui pense à la même blague que toi là maintenant 😄` },
    { id: 'bff_g4_04', text: `"Joyeux anniversaire. On a un signal pour dire que c'est trop sans rien dire." Un regard. Un mot. Un geste. Une façon de poser la question. Ce code qui veut dire on part dans dix minutes ou c'est insupportable ici ou sauve-moi. Ce système d'urgence silencieux développé par nécessité. Joyeux anniversaire, {prenom}.\nAvec gratitude pour ce système qui nous a sauvés de nombreuses situations, — Quelqu'un qui a activé ce signal plusieurs fois et toujours trouvé une réponse 🚨` },
    { id: 'bff_g4_05', text: `"Joyeux anniversaire. On a des règles implicites qu'on a jamais dites à voix haute." Pas de contrat. Pas de discussion. Ces règles qui se sont établies d'elles-mêmes. Ce qu'on fait. Ce qu'on ne fait pas. Comment on gère certaines situations. Ces conventions tacites qui font fonctionner ce qu'on est l'un pour l'autre. Joyeux anniversaire, {prenom}.\nAvec respect pour ces règles non dites et pour le fait qu'elles fonctionnent, — Quelqu'un qui a compris les règles sans qu'on les explique et les respecte toujours 📜` },
    { id: 'bff_g4_06', text: `"Joyeux anniversaire. On a une façon de se dire que quelque chose va pas sans le dire." Un ton. Une formule. Une façon de formuler une question banale qui veut dire autre chose. Ce code émotionnel. Cette façon de vérifier sans faire peur. De demander sans demander directement. Joyeux anniversaire, {prenom}.\nAvec gratitude pour ce code qui permet de vérifier sans brusquer, — Quelqu'un qui utilise ce code régulièrement et apprécie qu'il fonctionne dans les deux sens 🔐` },
    { id: 'bff_g4_07', text: `"Joyeux anniversaire. On a des références à des choses qui n'existent plus." Des endroits fermés. Des émissions arrêtées. Des personnes parties. Des périodes révolues. Et on continue de les citer. Comme si elles existaient encore dans notre espace commun. Parce que pour nous elles existent encore. Joyeux anniversaire, {prenom}.\nAvec pensée pour tous ces fantômes bienveillants de notre vocabulaire commun, — Quelqu'un qui continue de citer des choses que personne d'autre ne comprend 👻` },
    { id: 'bff_g4_08', text: `"Joyeux anniversaire. On a une histoire sur les débuts qu'on raconte différemment selon l'audience." La version courte. La version longue. La version pour les gens qu'on connaît peu. La version complète pour les rares. Ces couches de récit selon le contexte. Et la vraie version qu'on est les seuls à connaître entièrement. Joyeux anniversaire, {prenom}.\nAvec pensée pour la vraie version et pour tous ceux qui n'ont eu que les autres, — Quelqu'un qui connaît la version complète et la garde précieusement 📚` },
    { id: 'bff_g4_09', text: `"Joyeux anniversaire. On a un endroit qui est le nôtre." Pas forcément beau. Pas forcément spécial pour d'autres. Mais pour nous c'est quelque chose. Un café. Un quartier. Un trajet. Un endroit qui porte des souvenirs de nous. Qui dit quelque chose sur ce qu'on est ensemble. Joyeux anniversaire, {prenom}.\nAvec pensée pour cet endroit et ce qu'il représente dans notre géographie commune, — Quelqu'un qui pense à cet endroit parfois et ressent quelque chose 📍` },
    { id: 'bff_g4_10', text: `"Joyeux anniversaire. On a une façon de se dire qu'on s'ennuie quelque part." Un message codé. Une formulation convenue. Ce petit signal qui veut dire viens me chercher ou appelle-moi dans cinq minutes ou j'ai besoin d'une sortie de secours. Ce protocole d'évacuation sociale discret. Joyeux anniversaire, {prenom}.\nAvec gratitude pour toutes les fois où ce signal a été activé et reçu, — Quelqu'un qui a répondu à ce signal dans des délais raisonnables et recommencerait 📲` },
    { id: 'bff_g4_11', text: `"Joyeux anniversaire. On a des choses qu'on commande automatiquement pour l'autre." Au café. Au restaurant. Quand l'autre arrive en retard. Quand on sait ce qu'il ou elle voudrait. Cette connaissance des préférences. Cette façon de prendre soin sans demander. Joyeux anniversaire, {prenom}.\nAvec pensée pour toutes les commandes passées en ton nom avec succès, — Quelqu'un qui commande pour toi sans se tromper depuis longtemps ☕` },
    { id: 'bff_g4_12', text: `"Joyeux anniversaire. On a une façon de se dire qu'on est fiers l'un de l'autre." Pas toujours avec ces mots-là. Parfois une phrase. Un regard. Un message court. Une façon de mentionner quelque chose que l'autre a fait. Ce code de la fierté partagée qui n'a pas besoin de grands discours. Joyeux anniversaire, {prenom}.\nAvec fierté ce soir exprimée dans notre façon à nous, — Quelqu'un qui est fier de toi et le dit aujourd'hui dans tous les codes disponibles 🌟` },
    { id: 'bff_g4_13', text: `"Joyeux anniversaire. On a des discussions interrompues qu'on reprend des semaines après." Comme si elles n'avaient pas été interrompues. Comme si le temps entre les deux n'existait pas. On reprend exactement là où on était. Sans résumé. Sans introduction. La conversation continue. Joyeux anniversaire, {prenom}.\nAvec une conversation en cours quelque part qu'on reprendra probablement bientôt, — Quelqu'un qui reprendra exactement là où on s'est arrêtés au prochain message 💬` },
    { id: 'bff_g4_14', text: `"Joyeux anniversaire. On a un film ou une série qui est le nôtre." Qu'on a regardé ensemble. Ou dont on a parlé tellement qu'il fait partie du vocabulaire. Dont on cite des lignes. Dont on fait des références. Qui dit quelque chose sur ce qu'on est ensemble ou sur ce qu'on trouve drôle ou sur une période de notre vie. Joyeux anniversaire, {prenom}.\nAvec pensée pour ce film ou cette série et ce qu'elle représente dans notre univers commun, — Quelqu'un qui peut citer des répliques précises et sait que tu les connais aussi 🎬` },
    { id: 'bff_g4_15', text: `"Joyeux anniversaire. On a un mot pour les situations inconfortables." Ce mot ou cette phrase qui veut dire c'est gênant ici ou je savais pas quoi dire ou cette personne était insupportable. Ce code de l'inconfort social qui nous permet d'en parler en public sans que les autres comprennent. Joyeux anniversaire, {prenom}.\nAvec gratitude pour ce code qui a sauvé de nombreuses situations, — Quelqu'un qui a utilisé ce mot au moins deux fois cette semaine 😬` },
    { id: 'bff_g4_16', text: `"Joyeux anniversaire. On a une façon de se préparer mutuellement à une mauvaise nouvelle." Une formulation. Un ton. Une façon d'introduire quelque chose. Ce signal qui dit prépare-toi ce que je vais dire est difficile. Et qui donne à l'autre le temps de se préparer avant. Joyeux anniversaire, {prenom}.\nAvec gratitude pour ce signal qui a rendu les mauvaises nouvelles plus douces, — Quelqu'un qui reconnaît ce signal immédiatement et se prépare automatiquement 💙` },
    { id: 'bff_g4_17', text: `"Joyeux anniversaire. On a des opinions communes sur des gens qu'on exprime juste entre nous." Pas méchamment. Mais honnêtement. Ces verdicts partagés. Ces analyses communes. Ce tribunal privé où on dit ce qu'on pense vraiment des gens autour de nous. Joyeux anniversaire, {prenom}, mon assesseur.\nAvec pensée pour tous les verdicts rendus dans ce tribunal privé au fil des années, — Quelqu'un qui siège dans ce tribunal avec toi et trouve les délibérations toujours intéressantes ⚖️` },
    { id: 'bff_g4_18', text: `"Joyeux anniversaire. On a une chanson." Pas forcément choisie. Arrivée par circonstance. Par une soirée. Par un trajet. Par un moment où elle jouait et où quelque chose se passait. Et maintenant quand elle arrive quelque part elle veut dire quelque chose. Elle dit nous. Joyeux anniversaire, {prenom}.\nAvec pensée pour cette chanson et pour le moment où elle est devenue la nôtre, — Quelqu'un qui l'entend encore et pense à ce moment précis 🎵` },
    { id: 'bff_g4_19', text: `"Joyeux anniversaire. On a un niveau d'honnêteté qu'on a avec personne d'autre." Ce niveau. Où on peut dire des choses qui seraient mal interprétées ailleurs. Où le contexte est assez solide pour supporter n'importe quel mot. Où la confiance est assez profonde pour que la vérité soit safe. Ce niveau-là est rare. Joyeux anniversaire, {prenom}.\nAvec gratitude pour ce niveau d'honnêteté et pour tout ce qu'il a fallu construire pour y arriver, — Quelqu'un qui apprécie de pouvoir tout dire et qui use de ce privilège avec soin 💎` },
    { id: 'bff_g4_20', text: `"Joyeux anniversaire. Tout ce qu'on a construit ensemble est intraduisible." Si quelqu'un demandait d'expliquer. De mettre des mots sur ce qu'on est l'un pour l'autre. Sur notre langage. Sur nos codes. Sur notre histoire. Ça prendrait trop longtemps. Et ça serait jamais tout à fait juste. Parce que certaines choses n'existent que de l'intérieur. Joyeux anniversaire, {prenom}.\nAvec gratitude pour tout ce qui est intraduisible et pour ça précisément, — Quelqu'un qui vit de l'intérieur et ne voudrait pas être ailleurs ❤️` },
  ],
};

const BFF_G5: BirthdaySubGroup = {
  id: 'bff_g5',
  title: 'Ce que je sais sur toi que personne ne sait',
  messages: [
    { id: 'bff_g5_01', text: `"Joyeux anniversaire. Je sais des choses." Pas pour faire peur. Pas pour menacer. Juste pour que tu saches que je sais. Ces informations accumulées au fil des années. Ces confidences. Ces observations. Ces moments où t'étais toi-même sans filtre. Cette connaissance. Elle est là. Joyeux anniversaire, {prenom}.\nAvec pouvoir exercé avec bienveillance et discrétion depuis toujours, — Quelqu'un qui utilise cette connaissance pour ton bien exclusivement 🗝️` },
    { id: 'bff_g5_02', text: `"Joyeux anniversaire. Je sais ce qui te fait vraiment peur." Pas les peurs que tu avoues. Les vraies. Celles que tu nommes pas directement. Celles qui se cachent derrière les décisions. Derrière certains évitements. Derrière certaines réactions disproportionnées. Je les vois. Je les connais. Je n'en parle pas. Joyeux anniversaire, {prenom}.\nAvec respect total pour ces peurs et engagement de ne jamais les utiliser contre toi, — Quelqu'un qui connaît tes vraies peurs et choisit de ne jamais s'en servir 🤍` },
    { id: 'bff_g5_03', text: `"Joyeux anniversaire. Je sais que tu es plus sensible que tu le montres." La façade. Elle est bonne. Convaincante. La plupart des gens la prennent pour la réalité. Moi je sais ce qu'il y a derrière. Cette sensibilité que tu protèges. Ces choses qui t'atteignent vraiment et que tu gères en silence. Joyeux anniversaire, {prenom}.\nAvec respect pour cette sensibilité et pour la façon dont tu la portes, — Quelqu'un qui voit derrière la façade et aime les deux versions 💛` },
    { id: 'bff_g5_04', text: `"Joyeux anniversaire. Je sais ce que tu veux vraiment dans ta vie." Pas ce que tu dis que tu veux. Ce que tu veux vraiment. Ces désirs profonds que tu formules rarement. Que tu minimises parfois. Que tu transformes en ambitions raisonnables pour qu'ils soient plus acceptables. Moi je connais la version non éditorisée. Joyeux anniversaire, {prenom}.\nAvec espoir sincère que tu te rapproches de ce que tu veux vraiment, — Quelqu'un qui croit que tu mérites la version non éditorisée de ta propre vie 🌟` },
    { id: 'bff_g5_05', text: `"Joyeux anniversaire. Je sais pourquoi tu as fait ce choix dont tu parles pas." Ce choix. Ce truc qui s'est passé. Que tu as décidé. Que tu as peu expliqué. Que les autres ont interprété à leur façon. Moi je sais les vraies raisons. Parce que tu me les as dites. Ou parce que je t'ai assez vu pour les deviner. Joyeux anniversaire, {prenom}.\nAvec compréhension totale des raisons vraies derrière ce choix, — Quelqu'un qui comprend et qui a toujours compris même quand tu expliquais pas 🧩` },
    { id: 'bff_g5_06', text: `"Joyeux anniversaire. Je sais ce qui te rend fier de toi en secret." Ces choses que tu fais. Que tu banalises devant les autres. Dont tu parles peu. Mais dont tu es vraiment fier en silence. Ces petites victoires intérieures. Ces accomplissements discrets. Je les connais. Joyeux anniversaire, {prenom}.\nAvec fierté partagée pour ces choses que tu ne célèbres pas assez, — Quelqu'un qui est fier de ces mêmes choses et le dit aujourd'hui 🏅` },
    { id: 'bff_g5_07', text: `"Joyeux anniversaire. Je sais comment tu te comportes quand tu es vraiment heureux." C'est différent du bonheur affiché. Plus discret parfois. Plus physique. Une façon de bouger. De parler. De regarder les choses. Quand tu es vraiment heureux ça se voit autrement. Et moi je sais reconnaître cette version-là. Joyeux anniversaire, {prenom}.\nAvec espoir de voir cette version souvent et joie quand elle apparaît, — Quelqu'un qui guette cette version et la reconnaît toujours 😊` },
    { id: 'bff_g5_08', text: `"Joyeux anniversaire. Je sais ce que tu penses de toi-même les mauvais jours." Ces pensées que tu gardes pour toi. Ces jugements que tu te portes quand ça va pas. Cette voix intérieure peu bienveillante. Je sais qu'elle existe. Je sais ce qu'elle dit. Et je suis pas d'accord avec elle. Joyeux anniversaire, {prenom}.\nAvec désaccord ferme et documenté avec ta voix intérieure les mauvais jours, — Quelqu'un qui a une contre-expertise disponible sur ta valeur réelle à tout moment ⚖️` },
    { id: 'bff_g5_09', text: `"Joyeux anniversaire. Je sais que tu t'ennuies plus vite que tu le montres." Dans certaines situations. Avec certaines personnes. T'es là. Tu fais l'effort. Tu es poli et présent et attentif. Et tu t'ennuies. Et personne le voit. Moi si. Parce que je connais la différence entre toi vraiment là et toi poliment là. Joyeux anniversaire, {prenom}.\nAvec complicité pour tous ces moments de présence polie que je reconnaissais de loin, — Quelqu'un qui sait exactement dans quelles situations tu t'ennuies et garde ça pour lui 😴` },
    { id: 'bff_g5_10', text: `"Joyeux anniversaire. Je sais ce que tu aurais voulu faire et que tu as pas fait." Ce truc. Cette voie. Cette chose que t'as envisagée. Qu'était possible à un moment. Que t'as pas prise pour des raisons valables ou moins valables. Qui existe encore quelque part dans un coin. Joyeux anniversaire, {prenom}.\nAvec espace pour cette chose non faite sans jugement et sans pression, — Quelqu'un qui pense que certaines choses peuvent encore se faire et qui le dit doucement 🌱` },
    { id: 'bff_g5_11', text: `"Joyeux anniversaire. Je sais comment tu gères la solitude." Pas ce que tu en dis. Comment tu la vis vraiment. Ces moments à toi. Ce que tu fais dedans. Comment tu te parles. Ce que tu aimes dans ces moments et ce qui est plus difficile. Cette connaissance de ton rapport à toi-même. Joyeux anniversaire, {prenom}.\nAvec respect pour ton rapport à la solitude et pour ce qu'il dit sur qui tu es, — Quelqu'un qui connaît ta solitude et la respecte autant que ta présence 🌙` },
    { id: 'bff_g5_12', text: `"Joyeux anniversaire. Je sais ce que tu n'oublies jamais même si tu fais semblant." Ces trucs. Ces moments. Ces mots qui ont été dits. Ces choses qui se sont passées. Que tu gardes. Que tu portes. Que tu mentionnes plus mais qui sont là. Cette mémoire sélective des choses importantes que tu fais semblant d'avoir lâchées. Joyeux anniversaire, {prenom}.\nAvec compréhension de ce que tu portes en silence et respect pour cette façon de porter, — Quelqu'un qui sait ce que tu n'as pas oublié et qui ne le dira pas 🤫` },
    { id: 'bff_g5_13', text: `"Joyeux anniversaire. Je sais ce qui te manque en ce moment." Pas ce que tu demandes. Ce qui manque vraiment. Ce vide précis. Cette chose ou cette personne ou cette période. Ce manque que tu gères. Que tu contournes. Que tu nommes rarement. Je le vois. Joyeux anniversaire, {prenom}.\nAvec espace pour ce manque et présence dans ce qu'il reste malgré lui, — Quelqu'un qui ne peut pas combler ce manque mais qui peut rester à côté 🤝` },
    { id: 'bff_g5_14', text: `"Joyeux anniversaire. Je sais comment tu agis quand tu veux quelque chose sans le demander." Cette stratégie. Ces indices que tu sèmes. Ces façons de mentionner quelque chose sans le demander directement. J'ai appris à lire ces signaux. À les décoder. À répondre avant que tu aies à demander parfois. Joyeux anniversaire, {prenom}.\nAvec décodage des signaux maîtrisé et taux de réponse correct, — Quelqu'un qui lit tes signaux depuis longtemps et essaie d'y répondre avant la demande 🔍` },
    { id: 'bff_g5_15', text: `"Joyeux anniversaire. Je sais ce que tu penses de certaines personnes que tu ne peux pas dire." Ces opinions. Retenues par politesse. Par contexte. Par obligation sociale. Ces vrais ressentis que tu gardes. Et qui sortent parfois dans des conversations privées avec moi. Ce niveau de franchise qui n'existe qu'ici. Joyeux anniversaire, {prenom}.\nAvec confidentialité totale maintenue sur tout ce qui a été dit dans ces conversations, — Quelqu'un qui garde tout ça et ne le ressortira que dans les moments appropriés 🗄️` },
    { id: 'bff_g5_16', text: `"Joyeux anniversaire. Je sais que tu cherches encore certaines réponses." Ces questions. Sur toi. Sur ce que tu veux. Sur qui tu es vraiment. Sur ce qui compte. T'as avancé. T'as trouvé beaucoup. Mais il y a des questions qui restent ouvertes. Et c'est bien que ce soit ouvert. Et je sais lesquelles. Joyeux anniversaire, {prenom}.\nAvec respect pour les questions ouvertes et pour la personne qui les porte, — Quelqu'un qui a ses propres questions ouvertes et trouve du réconfort à les porter ensemble 💭` },
    { id: 'bff_g5_17', text: `"Joyeux anniversaire. Je sais ce que tu es vraiment fier d'avoir surmonté." Ces épreuves. Que t'as traversées. Dont tu parles peu maintenant. Mais dont tu sais au fond que c'était difficile et que tu t'en es sorti. Cette fierté silencieuse. Ces victoires intérieures que personne ne célèbre parce que personne savait vraiment ce que c'était. Joyeux anniversaire, {prenom}.\nAvec célébration de ces victoires aujourd'hui par quelqu'un qui sait ce qu'elles ont coûté, — Quelqu'un qui était là pendant et qui célèbre avec toi ce soir 🏆` },
    { id: 'bff_g5_18', text: `"Joyeux anniversaire. Je sais ce qui te fait te sentir vraiment compris." Ce n'est pas pareil pour tout le monde. Pour toi c'est quelque chose de précis. Une façon de répondre. Une question posée d'une certaine manière. Un silence au bon moment. Je sais ce qui dit à ton cerveau quelqu'un me voit vraiment. Joyeux anniversaire, {prenom}.\nAvec effort pour faire ça aujourd'hui d'une façon qui compte, — Quelqu'un qui essaie de te faire sentir vraiment compris ce soir et espère y arriver 🌟` },
    { id: 'bff_g5_19', text: `"Joyeux anniversaire. Je sais que tu es différent avec moi qu'avec les autres." Une version de toi. Spécifique. Qui n'existe que dans cet espace. Que d'autres ne voient pas. Que tu te permets ici. Cette version-là je la chéris. Parce qu'elle dit que tu me fais confiance assez pour être toi vraiment. Joyeux anniversaire, {prenom}.\nAvec gratitude pour cette version exclusive et pour la confiance qu'elle représente, — Quelqu'un qui reçoit cette version comme un cadeau chaque fois 💛` },
    { id: 'bff_g5_20', text: `"Joyeux anniversaire. Tout ce que je sais sur toi je le garde." Pas comme un pouvoir. Comme une responsabilité. Ces confidences. Ces faiblesses. Ces moments. Ces vérités. Tout ce que t'as mis dans mes mains au fil du temps. Je le garde. Soigneusement. Comme quelque chose de précieux. Parce que ça l'est. Joyeux anniversaire, {prenom}.\nAvec engagement renouvelé de garder tout ce qui m'a été confié, — Quelqu'un à qui tu peux continuer de tout dire et qui continuera de tout garder ❤️` },
  ],
};

const BFF_G6: BirthdaySubGroup = {
  id: 'bff_g6',
  title: 'La façon dont tu m\'as changé',
  messages: [
    { id: 'bff_g6_01', text: `"Joyeux anniversaire. Tu m'as changé et je pense que tu le sais pas vraiment." Pas d'un coup. Progressivement. Sans le chercher. Sans théorie ni intention. Juste en étant là. En disant certaines choses. En faisant certains choix. En étant toi. Et moi j'ai changé. En partie à cause de toi. Joyeux anniversaire, {prenom}.\nAvec reconnaissance pour un changement qui s'est fait en douceur et dans la bonne direction, — Quelqu'un qui est en partie qui il est grâce à toi et le sait 🌱` },
    { id: 'bff_g6_02', text: `"Joyeux anniversaire. T'as changé ma façon d'écouter." Avant je répondais trop vite. Je préparais ma réponse pendant que l'autre parlait encore. T'as quelque chose dans ta façon d'écouter qui m'a appris quelque chose. Cette façon d'être vraiment là. J'y arrive pas toujours. Mais j'essaie plus qu'avant. Joyeux anniversaire, {prenom}.\nAvec gratitude pour cette leçon reçue sans cours et appliquée imparfaitement mais sincèrement, — Quelqu'un qui écoute mieux grâce à toi et continue d'apprendre 👂` },
    { id: 'bff_g6_03', text: `"Joyeux anniversaire. T'as changé ce que je considère comme une vraie amitié." J'avais une définition avant. Approximative. T'as recalibré ça. Par l'exemple. Par ce que t'as fait. Par ce que t'es. Maintenant mes attentes sont différentes. Pas plus hautes. Mieux calibrées. Joyeux anniversaire, {prenom}, ma référence.\nAvec conscience que tu as redéfini ce que l'amitié peut être concrètement, — Quelqu'un dont tu as changé les standards pour le mieux 📏` },
    { id: 'bff_g6_04', text: `"Joyeux anniversaire. T'as changé ma façon de voir un truc que je voyais mal." Un sujet. Une question. Une façon de penser quelque chose. T'avais une perspective différente. T'as pas cherché à me convaincre. T'as juste dit ce que tu pensais. Et quelque chose a bougé. Et j'ai vu autrement. Joyeux anniversaire, {prenom}.\nAvec gratitude pour les perspectives qui font bouger les choses sans forcer, — Quelqu'un qui pense différemment sur au moins une chose grâce à toi 🔄` },
    { id: 'bff_g6_05', text: `"Joyeux anniversaire. T'as changé ma façon de m'autoriser des choses." Il y avait des trucs que je me permettais pas. Par habitude. Par peur. Par croyance que c'était pas pour moi. Et en te regardant faire. En t'entendant dire certaines choses. Quelque chose s'est autorisé. Joyeux anniversaire, {prenom}.\nAvec gratitude pour les permissions données par l'exemple, — Quelqu'un qui s'autorise plus de choses maintenant et pense à toi en le faisant 🚪` },
    { id: 'bff_g6_06', text: `"Joyeux anniversaire. T'as changé ma façon de gérer les conflits." Avant j'évitais. Ou j'explosais. T'as une troisième voie. Ni l'une ni l'autre. Quelque chose de plus direct. De plus calme. De plus honnête. J'y arrive pas toujours. Mais t'as montré que c'était possible. Joyeux anniversaire, {prenom}.\nAvec reconnaissance pour cette troisième voie montrée par l'exemple, — Quelqu'un qui essaie de faire pareil et réussit de mieux en mieux 🕊️` },
    { id: 'bff_g6_07', text: `"Joyeux anniversaire. T'as changé ce que je crois être possible." Il y a des choses que je pensais pas accessibles. Pas pour moi. Pas dans ma vie. T'en as fait certaines. Et en te regardant je me suis dit si pour toi pourquoi pas pour moi. Ce changement de ce qui est possible. Joyeux anniversaire, {prenom}.\nAvec gratitude pour l'élargissement du champ des possibles opéré par ta seule existence, — Quelqu'un dont les horizons sont plus larges grâce à toi 🌅` },
    { id: 'bff_g6_08', text: `"Joyeux anniversaire. T'as changé ma façon de prendre soin des gens." J'étais moins attentif avant. Moins présent dans les détails. T'as quelque chose dans ta façon de remarquer. De te souvenir. De vérifier. Ça a déteint. Lentement. Joyeux anniversaire, {prenom}.\nAvec reconnaissance pour ce que j'ai appris en te regardant prendre soin des autres, — Quelqu'un qui prend mieux soin des gens depuis qu'il te connaît 🤲` },
    { id: 'bff_g6_09', text: `"Joyeux anniversaire. T'as changé ma relation à ce que je mérite." J'acceptais des choses que j'aurais pas dû accepter. T'en as parlé. Pas toujours directement. Parfois juste en refusant toi de certaines choses. En montrant que c'est possible d'exiger mieux. Joyeux anniversaire, {prenom}.\nAvec gratitude pour les standards relevés sans leçon donnée, — Quelqu'un qui accepte mieux ce qu'il mérite depuis qu'il te connaît ⭐` },
    { id: 'bff_g6_10', text: `"Joyeux anniversaire. T'as changé ma façon de rire." Pas le mécanisme. La fréquence. Le type. Les choses que je trouve drôles. T'as un sens de l'humour particulier. Qui a déteint. Qui a calibré le mien différemment. Mes blagues maintenant ont une trace de toi dedans. Joyeux anniversaire, {prenom}.\nAvec reconnaissance pour le calibrage de mon humour et ses résultats globalement positifs, — Quelqu'un dont l'humour porte une part de toi et en est content 😄` },
    { id: 'bff_g6_11', text: `"Joyeux anniversaire. T'as changé ce que je considère comme du courage." J'avais une définition. Les grandes choses. Les actes spectaculaires. T'as montré une autre version. Les petits courages quotidiens. Ceux qu'on voit pas. Ceux qui coûtent quand même. Joyeux anniversaire, {prenom}, expert en petits courages.\nAvec redéfinition du courage opérée par tes exemples discrets, — Quelqu'un qui reconnaît maintenant le courage là où il l'aurait pas vu avant 🦁` },
    { id: 'bff_g6_12', text: `"Joyeux anniversaire. T'as changé ma façon de penser à la loyauté." Ce mot. Ce concept. T'en as une version concrète. Ancrée dans des actes. Dans des présences. Dans des silences maintenus. Dans des choix répétés. T'as changé comment je comprends ça et comment j'essaie de le pratiquer. Joyeux anniversaire, {prenom}.\nAvec gratitude pour cette définition de la loyauté vécue de l'intérieur, — Quelqu'un qui comprend mieux ce mot depuis qu'il te connaît 🤝` },
    { id: 'bff_g6_13', text: `"Joyeux anniversaire. T'as changé ma façon d'être présent." Présent vraiment. Pas juste physiquement là. Présent dans l'attention. Dans ce qu'on remarque. Dans ce qu'on retient. T'as une façon d'être là qui m'a appris quelque chose sur ce que ça veut vraiment dire. Joyeux anniversaire, {prenom}.\nAvec reconnaissance pour cette leçon de présence reçue par osmose, — Quelqu'un qui essaie d'être plus vraiment là grâce à ton exemple 🌿` },
    { id: 'bff_g6_14', text: `"Joyeux anniversaire. T'as changé ce que je pense de moi-même." Pas tout. Des parties. Ces parties que tu voyais bien avant que je les voie. Ces qualités que tu nommais quand je les niais. Ces forces que tu rappelais quand j'en avais besoin. T'as participé à comment je me vois. Joyeux anniversaire, {prenom}.\nAvec reconnaissance pour le rôle joué dans mon image de moi-même, — Quelqu'un qui se voit différemment en partie parce que tu l'as regardé autrement 🪞` },
    { id: 'bff_g6_15', text: `"Joyeux anniversaire. T'as changé ma façon de traverser les moments difficiles." Avant je gérais seul. Ou j'attendais que ça passe. T'as montré qu'on peut traverser des choses avec quelqu'un. Que partager une difficulté la change. Que la présence de l'autre fait quelque chose de réel. Joyeux anniversaire, {prenom}.\nAvec gratitude pour cette leçon sur la traversée des moments difficiles, — Quelqu'un qui traverse plus facilement depuis qu'il sait que tu es là 💪` },
    { id: 'bff_g6_16', text: `"Joyeux anniversaire. T'as changé ma façon de dire merci." Je le disais pas assez. Ou de façon automatique. Toi tu le dis précisément. Pour quelque chose de spécifique. Ça change tout. J'essaie de faire pareil. Joyeux anniversaire, {prenom}, et merci pour cette leçon précise.\nAvec merci spécifique pour cette leçon sur la spécificité du merci, — Quelqu'un qui dit merci différemment depuis qu'il t'a observé le dire 🙏` },
    { id: 'bff_g6_17', text: `"Joyeux anniversaire. T'as changé ma façon de laisser les gens être eux-mêmes." J'avais des attentes. Sur comment les gens devraient être. Réagir. Penser. T'as une façon d'accepter les gens comme ils sont qui m'a appris quelque chose. Ce lâcher prise sur ce que les autres devraient être. Joyeux anniversaire, {prenom}.\nAvec gratitude pour cette leçon d'acceptation qui continue de m'être utile, — Quelqu'un qui juge moins et accepte plus depuis qu'il te connaît 🌸` },
    { id: 'bff_g6_18', text: `"Joyeux anniversaire. T'as changé ma façon de me battre pour les choses qui comptent." Je capitulais trop vite parfois. Ou au mauvais moment. T'as une façon de tenir sur ce qui est important. De pas lâcher quand c'est vraiment là que ça se joue. Ça a déteint. Joyeux anniversaire, {prenom}.\nAvec gratitude pour cette leçon sur quand tenir et quand lâcher, — Quelqu'un qui se bat mieux pour les bonnes choses depuis qu'il t'a observé 🥊` },
    { id: 'bff_g6_19', text: `"Joyeux anniversaire. T'as changé ma façon de croire que les bonnes choses durent." J'étais plus sceptique. Sur la durée des liens. Sur la loyauté dans le temps. Sur la possibilité que quelque chose de bien résiste. T'as prouvé par l'exemple que c'est possible. Joyeux anniversaire, {prenom}.\nAvec gratitude pour cette preuve vivante que les bonnes choses peuvent durer, — Quelqu'un qui croit en la durée des bonnes choses grâce à toi ⏳` },
    { id: 'bff_g6_20', text: `"Joyeux anniversaire. Je suis une meilleure personne depuis que je te connais." Pas dramatiquement. Pas révolutionnairement. Progressivement. Dans des détails. Dans des façons de faire. Dans des façons d'être. Dans ce que je considère important. Dans ce que je refuse. Dans ce que j'accepte. T'y es pour quelque chose. Joyeux anniversaire, {prenom}.\nAvec gratitude simple et vraie pour ce que ta présence a fait de moi, — Quelqu'un qui est content d'être qui il est en partie grâce à toi ❤️` },
  ],
};

const BFF_G7: BirthdaySubGroup = {
  id: 'bff_g7',
  title: 'Tout ce qu\'on a traversé ensemble',
  messages: [
    { id: 'bff_g7_01', text: `"Joyeux anniversaire. On a traversé des choses." Pas juste vécu. Traversé. Avec ce que ça implique de résistance. De durée. De sortie de l'autre côté. Ces expériences qui ont un avant et un après. Ces périodes qui laissent une trace. Ces moments dont on parle encore ou dont on ne parle plus jamais. Joyeux anniversaire, {prenom}.\nAvec respect pour tout ce que traverser des choses ensemble demande, — Quelqu'un qui était là pendant et qui est là après et qui sera là pour les prochaines 🌊` },
    { id: 'bff_g7_02', text: `"Joyeux anniversaire. On a traversé une rupture." La tienne. Ou les tiennes. Ces périodes. Ces appels. Ces conversations qui duraient. Ces soirs difficiles. Ces matins après. J'étais là. Pas toujours avec les bons mots. Mais là. Avec le temps qu'il fallait. Joyeux anniversaire, {prenom}.\nAvec mémoire de ces périodes et de ce qu'elles ont demandé à tous les deux, — Quelqu'un qui était là pendant ces soirs et qui t'a vu ressortir de l'autre côté 💙` },
    { id: 'bff_g7_03', text: `"Joyeux anniversaire. On a traversé une période où tout allait mal en même temps." Pas juste pour toi. Pour nous deux peut-être. Ou juste pour toi et moi j'essayais de tenir. Ces périodes de densité difficile. Où plusieurs choses lourdes arrivaient ensemble. Et on gérais. Ensemble ou chacun de son côté mais ensemble quand même. Joyeux anniversaire, {prenom}.\nAvec respect pour ce que ces périodes demandaient de tenir debout, — Quelqu'un qui se souvient de ces périodes et de comment on en est sortis 💪` },
    { id: 'bff_g7_04', text: `"Joyeux anniversaire. On a traversé une grande joie." Pas seulement les difficultés. Les joies aussi se traversent. Ces moments de bonheur intense. Ces réussites. Ces nouvelles attendues. Ces surprises heureuses. J'étais là pour celles-là aussi. Et la joie partagée c'est différent. C'est mieux. Joyeux anniversaire, {prenom}.\nAvec pensée pour ces moments de joie partagée et ce qu'ils ont représenté, — Quelqu'un qui était là pour les joies aussi et qui les garde précieusement 🎉` },
    { id: 'bff_g7_05', text: `"Joyeux anniversaire. On a traversé un désaccord sérieux." Et on s'en est sortis. Pas facilement. Pas rapidement peut-être. Mais on s'en est sortis. Ces désaccords qui testent un lien. Qui disent si c'est vraiment solide. Le nôtre l'était. Joyeux anniversaire, {prenom}.\nAvec respect pour la solidité prouvée dans ce désaccord et pour ce qu'il a coûté, — Quelqu'un qui est content d'avoir tenu et de t'avoir en face encore aujourd'hui 🤝` },
    { id: 'bff_g7_06', text: `"Joyeux anniversaire. On a traversé une perte." Quelque chose ou quelqu'un. Ces moments où on perd quelque chose d'important. Ces deuils petits ou grands. J'étais là. T'étais là. On a tenu l'espace pour l'autre. On a laissé la tristesse exister sans chercher à la raccourcir. Joyeux anniversaire, {prenom}.\nAvec mémoire douce pour ce qu'on a perdu et pour comment on s'est tenus, — Quelqu'un qui pense encore à ça parfois et sait que toi aussi 💙` },
    { id: 'bff_g7_07', text: `"Joyeux anniversaire. On a traversé une longue distance." Géographique. Temporelle. Émotionnelle parfois. Ces périodes où le lien devait fonctionner autrement. Où on s'adaptait. Où quelque chose tenait sans la présence quotidienne. Et ça tenait. Joyeux anniversaire, {prenom}.\nAvec respect pour ce qui a tenu à distance et pour ce que ça a prouvé, — Quelqu'un qui a compris grâce à cette période que c'était solide pour de vrai ✈️` },
    { id: 'bff_g7_08', text: `"Joyeux anniversaire. On a traversé nos propres transformations." T'as changé. J'ai changé. On a changé pendant qu'on se connaissait. Et le lien s'est adapté. Il a suivi les transformations. Il ne ressemble pas à ce qu'il était au début. Il est mieux. Plus profond. Plus vrai. Joyeux anniversaire, {prenom}.\nAvec gratitude pour un lien assez vivant pour suivre les transformations, — Quelqu'un dont le lien avec toi a évolué et est meilleur pour ça 🌱` },
    { id: 'bff_g7_09', text: `"Joyeux anniversaire. On a traversé des périodes de silence." Des moments où on se parlait moins. Où la vie prenait beaucoup de place. Où le contact était sporadique. Et on reprenait. Toujours. Là où on s'était laissés. Comme si le silence avait pas entamé quelque chose d'essentiel. Joyeux anniversaire, {prenom}.\nAvec gratitude pour un lien assez solide pour survivre aux silences, — Quelqu'un qui reprend toujours là où on s'était arrêtés et le referait 🔄` },
    { id: 'bff_g7_10', text: `"Joyeux anniversaire. On a traversé des fous rires impossibles à expliquer." Ces moments. Ces situations absurdes. Ces choses qui n'auraient pas dû être drôles et qui l'étaient. Ces rires qui ne s'arrêtaient pas. Ces crises qui arrivaient au pire moment. Ces soirées où on avait mal au ventre d'avoir trop ri. Joyeux anniversaire, {prenom}.\nAvec sourire immédiat à la pensée de ces moments précis, — Quelqu'un qui rit encore en y pensant et sait que toi aussi 😂` },
    { id: 'bff_g7_11', text: `"Joyeux anniversaire. On a traversé des doutes sur nous." Des moments où c'était compliqué. Où on se demandait. Où quelque chose grinçait. Ces moments de fragilité dans le lien. Et on a continué. Choisi de continuer. Et c'était le bon choix. Joyeux anniversaire, {prenom}.\nAvec respect pour les choix faits dans les moments de doute, — Quelqu'un qui a choisi de continuer et ne le regrette pas 💛` },
    { id: 'bff_g7_12', text: `"Joyeux anniversaire. On a traversé des moments où l'un de nous avait besoin et l'autre donnait." Pas toujours équilibré en même temps. Parfois c'est toi qui donnais. Parfois c'est moi. Avec la confiance que ça se rééquilibre dans le temps. Cette économie de l'amitié où le bilan est sur le long terme. Joyeux anniversaire, {prenom}.\nAvec bilan du long terme qui s'équilibre et confiance que ça continuera, — Quelqu'un qui croit au bilan long terme et qui est là pour les prochains rééquilibrages ⚖️` },
    { id: 'bff_g7_13', text: `"Joyeux anniversaire. On a traversé des changements de vie majeurs." Les tiens. Les miens. Ces moments où tout change en même temps. Ces pivots. Ces renaissances. Ces réorganisations complètes. On était là l'un pour l'autre pendant. Et après. Et le lien a survécu à chaque réorganisation. Joyeux anniversaire, {prenom}.\nAvec respect pour la résilience de ce lien face aux grands changements, — Quelqu'un qui t'a suivi dans chaque version de ta vie et continuera 🔄` },
    { id: 'bff_g7_14', text: `"Joyeux anniversaire. On a traversé des nuits qui ont changé quelque chose." Ces nuits précises. Ces conversations de 3h du matin. Ces moments où quelque chose s'est dit ou s'est passé qui a changé la configuration. Ces nuits charnières. Joyeux anniversaire, {prenom}.\nAvec pensée pour ces nuits et pour ce qu'elles ont changé, — Quelqu'un qui se souvient de ces nuits et de ce qu'elles ont représenté 🌑` },
    { id: 'bff_g7_15', text: `"Joyeux anniversaire. On a traversé des années ordinaires." Pas seulement les grandes choses. Les années normales aussi. Les périodes sans événements majeurs. Ces années de vie quotidienne partagée. De conversations banales. De présences ordinaires. C'est ce fond-là qui fait le tissu de ce qu'on est. Joyeux anniversaire, {prenom}.\nAvec gratitude pour les années ordinaires et pour tout ce qu'elles contiennent, — Quelqu'un qui trouve les années ordinaires aussi précieuses que les autres 📆` },
    { id: 'bff_g7_16', text: `"Joyeux anniversaire. On a traversé des périodes où on riait de tout." Ces phases. Ces moments de légèreté absolue. Où tout était drôle. Où on trouvait le comique partout. Ces périodes de grâce légère. Joyeux anniversaire, {prenom}.\nAvec nostalgie douce pour ces périodes et espoir d'en avoir encore, — Quelqu'un qui cherche à retrouver ces périodes et y arrive parfois 😄` },
    { id: 'bff_g7_17', text: `"Joyeux anniversaire. On a traversé des moments où l'un de nous avait tort." Et l'autre avait raison. Et c'était géré. Avec plus ou moins de grâce selon les cas. Et ça n'a pas abîmé quelque chose d'essentiel. Cette façon de traverser les torts sans en faire une catastrophe. Joyeux anniversaire, {prenom}.\nAvec bilan équilibré des torts respectifs et paix avec le résultat, — Quelqu'un qui a eu tort parfois et qui sait que tu en as pas profité 🤍` },
    { id: 'bff_g7_18', text: `"Joyeux anniversaire. On a traversé des étapes de vie différentes en même temps." T'étais dans quelque chose. J'étais dans autre chose. Nos vies prenaient des formes différentes au même moment. Et on restait connectés malgré des réalités de plus en plus distinctes. Cette traversée parallèle. Joyeux anniversaire, {prenom}.\nAvec respect pour ce qu'il faut maintenir un lien quand les vies divergent, — Quelqu'un dont la vie est différente de la tienne et qui trouve ça beau que ça tienne 🌿` },
    { id: 'bff_g7_19', text: `"Joyeux anniversaire. On a traversé assez de choses pour savoir que ça tiendra encore." C'est ce que tout ça prouve. Ce bilan de ce qu'on a traversé. Ce n'est pas de la chance. C'est de la solidité. Construite. Éprouvée. Confirmée à chaque traversée. Joyeux anniversaire, {prenom}.\nAvec certitude tranquille que ça tiendra encore pour les traversées à venir, — Quelqu'un qui est convaincu de la solidité de ça et qui en est rassuré 🏗️` },
    { id: 'bff_g7_20', text: `"Joyeux anniversaire. Tout ce qu'on a traversé a construit quelque chose." Pas un monument. Quelque chose de plus discret. De plus intime. Cette connaissance mutuelle. Cette confiance. Cette façon d'être là l'un pour l'autre. Ce quelque chose qu'on a construit sans le nommer. Sans l'annoncer. En vivant simplement. Joyeux anniversaire, {prenom}.\nAvec gratitude pour tout ce qui a été construit sans qu'on s'en rende compte, — Quelqu'un qui est fier de ce qu'on a construit et de ce qu'on est l'un pour l'autre ❤️` },
  ],
};

