const SF_G1: BirthdaySubGroup = {
  id: 'sf_g1',
  title: 'Tu vieillis',
  messages: [
    { id: 'sf_g1_01', text: `"Joyeux anniversaire. On va pas se mentir." Tu as un an de plus. C'est mathématique. Implacable. Le calendrier ne négocie pas. J'ai regardé des photos de nous il y a dix ans et j'ai fermé l'application immédiatement. Pas par tristesse. Par instinct de survie. On vieillit tous les deux et on en parle jamais mais ce soir c'est ton anniversaire alors je te dis : tu vieillis bien. Relativement. Joyeux anniversaire, {prenom}.\nAvec honnêteté assumée et bienveillance relative, — Quelqu'un qui vieillit aussi et préfère ne pas y penser 🪞` },
    { id: 'sf_g1_02', text: `"Joyeux anniversaire. J'ai calculé." En années-chien tu serais mort depuis longtemps. En années-chat pareil. En années-humain tu es officiellement dans la deuxième moitié. Je dis pas ça pour être cruel. Je dis ça parce que quelqu'un devait le dire et que c'est mon rôle depuis qu'on se connaît. Joyeux anniversaire, {prenom}, tu es statistiquement en descente.\nAvec calculs vérifiés et affection sincère malgré les chiffres, — Quelqu'un qui sera là jusqu'à la fin de la descente 📉` },
    { id: 'sf_g1_03', text: `"Joyeux anniversaire. Tes genoux ont fait un bruit ce matin." Je sais pas si tu l'as entendu. Mais moi oui. Ce petit craquement en te levant. Ce son nouveau qui dit que ton corps commence à commenter ses propres mouvements. C'est le début d'une longue conversation entre toi et tes articulations. Profite de l'anniversaire. Tes genoux ont l'air d'avoir des choses à dire. Joyeux anniversaire, {prenom}.\nAvec attention portée aux signaux corporels et inquiétude préventive, — Quelqu'un qui a ses propres bruits mais préfère pas en parler 🦴` },
    { id: 'sf_g1_04', text: `"Joyeux anniversaire. J'ai regardé ce que tu aimais il y a quinze ans." La musique. Les films. Les sorties. Les gens que tu trouvais intéressants. J'ai comparé avec maintenant. Le résultat est soit une belle évolution soit une capitulation progressive selon l'angle choisi. J'ai choisi l'angle évolution pour ta fête. Joyeux anniversaire, {prenom}, tu as changé et c'est très bien.\nAvec analyse comparative sur quinze ans et conclusion bienveillante choisie délibérément, — Quelqu'un qui te connaît dans toutes tes versions 📼` },
    { id: 'sf_g1_05', text: `"Joyeux anniversaire. Tu parles de dormir différemment maintenant." Avant tu parlais de sorties. De projets. De ce que t'avais envie de faire. Maintenant dans tes meilleures histoires il y a souvent un bon lit. Un silence. Une nuit sans réveil. C'est pas un reproche. C'est une observation. Et entre nous je comprends totalement. Joyeux anniversaire, {prenom}, champion du sommeil assumé.\nAvec observation sociologique de l'évolution de tes priorités nocturnes, — Quelqu'un qui parle aussi de dormir maintenant et trouve ça très bien 🛏️` },
    { id: 'sf_g1_06', text: `"Joyeux anniversaire. T'as dit 'les jeunes' cette semaine." Je t'ai entendu. Tu parlais de quelqu'un. Et tu as dit les jeunes avec cette intonation. Celle qu'on avait juré de ne jamais avoir. Celle de nos parents. Celle qui dit qu'on est passé de l'autre côté sans vraiment s'en rendre compte. C'est officiel. Joyeux anniversaire, {prenom}, bienvenue de l'autre côté.\nAvec preuve audio mémorisée et passage de côté officiellement acté, — Quelqu'un qui a dit la même chose deux jours avant et ne s'en est pas excusé 👴` },
    { id: 'sf_g1_07', text: `"Joyeux anniversaire. Tu regardes le prix des choses différemment." Avant t'avais pas de budget vraiment. Maintenant tu compares. Tu vérifies. Tu dis c'était moins cher avant avec une certitude absolue même quand c'est faux. Et tu as des opinions sur les taux d'intérêt. Ça s'est passé progressivement et personne t'a prévenu. Joyeux anniversaire, {prenom}.\nAvec observation de ton évolution financière et solidarité de mes propres comparaisons de prix, — Quelqu'un qui vérifie aussi les prix maintenant et trouve ça tout à fait normal 💸` },
    { id: 'sf_g1_08', text: `"Joyeux anniversaire. Tes références culturelles datent." T'as fait une blague cette semaine. Elle était drôle. Mais la personne en face avait pas la référence. Parce qu'elle avait sept ans quand c'est sorti. T'as expliqué. L'explication était plus longue que la blague. Le moment était passé. C'est ça vieillir. Joyeux anniversaire, {prenom}.\nAvec documentaire sur la mort de tes références culturelles et respect pour ta persévérance, — Quelqu'un qui continue aussi de faire des blagues que personne comprend et s'en fout 📺` },
    { id: 'sf_g1_09', text: `"Joyeux anniversaire. T'as commencé à parler de ta santé." Pas de façon dramatique. Juste. Un truc qui fait un peu mal. Un bilan qui s'allonge. Une chose à surveiller. Ces conversations qu'on avait pas avant et qui s'glissent maintenant entre deux autres sujets. C'est normal. C'est l'âge. C'est humain. Mais c'est nouveau et on s'en souviendra. Joyeux anniversaire, {prenom}.\nAvec archivage de la date du premier vrai sujet santé dans notre amitié, — Quelqu'un qui a ses propres bilans et préfère changer de sujet aussi 🩺` },
    { id: 'sf_g1_10', text: `"Joyeux anniversaire. T'as raison sur des choses que t'avais tort avant." C'est ça aussi vieillir. Pas seulement les genoux et les références. Le fait d'avoir eu tort pendant des années sur des trucs et de finalement comprendre. Et d'être un peu gêné de l'admettre. Et de le faire quand même parce qu'on est adulte. Joyeux anniversaire, {prenom}, tu as eu tort et maintenant tu as raison et c'est très bien.\nAvec bilan de tes révisions intellectuelles et admiration pour leur direction générale, — Quelqu'un qui révise aussi et préfère ne pas faire la liste complète 🔄` },
    { id: 'sf_g1_11', text: `"Joyeux anniversaire. Tu connais le nom de ton médecin." Pas juste le cabinet. Le nom. Le prénom même. Tu peux le citer dans une phrase naturellement. C'est un signe. Un signe discret mais réel que quelque chose a changé. Avant t'allais aux urgences ou tu attendais que ça passe. Maintenant t'as un médecin. Avec un nom. Joyeux anniversaire, {prenom}.\nAvec salutation respectueuse à ton médecin dont tu connais maintenant le prénom, — Quelqu'un qui a aussi un médecin avec un prénom depuis peu 🏥` },
    { id: 'sf_g1_12', text: `"Joyeux anniversaire. T'as dit c'était mieux avant." Sur quelque chose. Je sais plus quoi exactement. Mais t'as dit cette phrase. Avec conviction. Avec nostalgie. Avec cette certitude douce que quelque chose d'avant était supérieur à quelque chose de maintenant. C'est le signe le plus classique. Joyeux anniversaire, {prenom}, tu es officiellement nostalgique.\nAvec acte officiel de ta première nostalgie documentée, — Quelqu'un qui est d'accord que c'était mieux avant sur au moins trois trucs 📻` },
    { id: 'sf_g1_13', text: `"Joyeux anniversaire. Tu vas te coucher avant minuit maintenant." Volontairement. Avec plaisir même. Tu annules des choses qui finissent trop tard. Tu planifies tes nuits. Tu parles de qualité du sommeil avec une expertise que t'aurais moquée il y a dix ans. Et tu te réveilles reposé et content. Joyeux anniversaire, {prenom}, champion de la nuit courte.\nAvec respect total pour tes nouvelles heures et jalousie à peine dissimulée, — Quelqu'un qui essaie aussi et y arrive pas encore complètement 🌙` },
    { id: 'sf_g1_14', text: `"Joyeux anniversaire. Tes photos de profil ont changé." Avant c'était des soirées. Des voyages. Des inconnus flous en arrière-plan. Maintenant c'est des couchers de soleil. Des repas bien dressés. Des moments calmes. Le fond a changé. L'arrière-plan a changé. Toi aussi. Joyeux anniversaire, {prenom}, ta vie a une meilleure lumière maintenant.\nAvec analyse chronologique de tes photos de profil et conclusion esthétiquement positive, — Quelqu'un dont les photos ont suivi exactement la même évolution 📸` },
    { id: 'sf_g1_15', text: `"Joyeux anniversaire. Tu planifies maintenant." Tu planes pas dans le sens où tu planes. Tu planifies. Tu anticipes. Tu confirmes plusieurs jours avant. Tu annules moins. Tu es quelqu'un de fiable avec un agenda et des créneaux. C'est soit de la maturité soit la mort de la spontanéité selon l'angle. J'ai choisi l'angle maturité. Joyeux anniversaire, {prenom}.\nAvec validation de ta transformation en personne fiable avec agenda, — Quelqu'un qui a aussi un agenda et trouve ça reposant 📅` },
    { id: 'sf_g1_16', text: `"Joyeux anniversaire. T'as un avis sur les matelas maintenant." Un vrai avis. Avec des arguments. Des marques citées. Une fermeté idéale défendue. Il y a un moment dans une vie où on développe une opinion sur les matelas et ce moment c'est passé pour toi. C'est pas un reproche. C'est un constat. Joyeux anniversaire, {prenom}, expert en literie.\nAvec respect pour ton expertise matelas et curiosité pour tes recommandations, — Quelqu'un qui a aussi des opinions sur les matelas et en est légèrement honteux 🛏️` },
    { id: 'sf_g1_17', text: `"Joyeux anniversaire. Tu ressembles à quelqu'un." Pas à quelqu'un de précis. À quelqu'un de ta famille. Ce truc qui arrive progressivement. Un geste. Une expression. Une façon de dire certaines choses. Et un jour quelqu'un dit tiens tu fais exactement comme ton père ou ta mère et tu peux plus ne pas voir. Joyeux anniversaire, {prenom}.\nAvec observation de la ressemblance émergente et solidarité familiale, — Quelqu'un à qui on dit la même chose et qui essaie de l'accepter 👨‍👩‍👧` },
    { id: 'sf_g1_18', text: `"Joyeux anniversaire. Tes vacances ont changé de forme." Avant c'était l'aventure. L'imprévu. Le sac sur le dos. Maintenant il y a un lit confortable dans l'équation. Peut-être un spa. Définitivement un bon restaurant. L'imprévu est toléré mais dans des limites raisonnables. Joyeux anniversaire, {prenom}, vacancier de l'excellence confortable.\nAvec validation totale de ton évolution vacancière et envie de t'accompagner, — Quelqu'un qui préfère aussi un bon lit maintenant et l'assume complètement 🏨` },
    { id: 'sf_g1_19', text: `"Joyeux anniversaire. Tu dis merci différemment." C'est subtil. Mais le merci a changé. Il est plus lourd. Plus conscient. Comme si avec les années tu avais compris que certaines choses méritent plus qu'un merci rapide. Que certaines présences méritent d'être nommées. Que certains gestes méritent d'être vus. Joyeux anniversaire, {prenom}, tu vieillis bien sur ce point-là.\nAvec observation de l'évolution qualitative de tes mercis et émotion à peine avouée, — Quelqu'un à qui tu as dit merci un jour d'une façon qui a compté 🙏` },
    { id: 'sf_g1_20', text: `"Joyeux anniversaire. T'es plus vieux que tu le crois et moins vieux que tu le penses." Les deux sont vrais en même temps. T'as plus d'années derrière toi que tu ne veux l'admettre. Et t'as plus d'énergie que tu ne le crois certains matins. T'es exactement où tu dois être. C'est ça le truc avec l'âge. On y est toujours au bon endroit même quand ça grince. Joyeux anniversaire, {prenom}.\nAvec paradoxe résolu et conclusion aussi douce qu'honnête, — Quelqu'un qui navigue le même paradoxe et te retrouve dedans ⚖️` },
  ],
};

const SF_G2: BirthdaySubGroup = {
  id: 'sf_g2',
  title: 'Tes défauts qu\'on connaît par cœur',
  messages: [
    { id: 'sf_g2_01', text: `"Joyeux anniversaire. On va faire le bilan." T'es en retard chronique. T'oublies les trucs importants sauf les trucs inutiles que tu retiens parfaitement. Tu réponds aux messages quand tu en as envie. Tu prends des décisions au dernier moment. Tu changes d'avis souvent. Et je suis toujours là. C'est soit de la loyauté soit un problème. Joyeux anniversaire, {prenom}.\nAvec bilan complet établi et présence maintenue malgré les éléments du dossier, — Quelqu'un qui a ses propres défauts et préfère ne pas faire le bilan comparatif 📋` },
    { id: 'sf_g2_02', text: `"Joyeux anniversaire. Tu écoutes pas jusqu'au bout." Tu commences à écouter. Vraiment. Puis à un moment ton cerveau part sur autre chose. Et tu réponds à quelque chose que j'ai pas dit. Ou tu poses une question dont j'avais donné la réponse trente secondes avant. Je sais que t'es là. Je sais que tu m'aimes. Mais tu écoutes pas jusqu'au bout. Joyeux anniversaire, {prenom}.\nAvec constat documenté sur de nombreuses années et amour intact malgré l'inattention, — Quelqu'un qui finit ses phrases quand même depuis tout ce temps 👂` },
    { id: 'sf_g2_03', text: `"Joyeux anniversaire. Tu dis que tu vas rappeler et tu rappelles pas." T'as une intention sincère au moment où tu le dis. Je sais ça. Je le vois sur ton visage. Et puis autre chose se passe. Et puis tu oublies. Et puis des jours passent. Et puis t'as un peu honte. Et puis tu rappelles pas quand même. C'est un cycle. On le connaît tous les deux. Joyeux anniversaire, {prenom}.\nAvec connaissance complète du cycle et attente zéro des rappels depuis longtemps, — Quelqu'un qui répond quand même quand tu finis par écrire 📞` },
    { id: 'sf_g2_04', text: `"Joyeux anniversaire. Tu dramatises." Pas tout. Mais certaines choses. Un problème moyen devient une catastrophe le temps de t'appeler. Puis ça se règle. Puis t'as presque oublié. Le pic émotionnel dure vingt minutes. Après tu vas bien. J'ai appris à calibrer. Je suis là pour le pic. Je suis là après. Joyeux anniversaire, {prenom}.\nAvec courbe de dramatisation mémorisée et présence garantie à tous les stades, — Quelqu'un qui a sa propre courbe et apprécie qu'on soit là pour les deux 🎢` },
    { id: 'sf_g2_05', text: `"Joyeux anniversaire. Tu te perds encore." Avec le GPS. Sans le GPS. Dans des endroits que tu connais. Dans des endroits nouveaux. T'as un talent particulier pour te retrouver dans la mauvaise rue avec la bonne conviction. J'ai arrêté de comprendre comment c'est possible. J'ai juste accepté que tu te perdes et que tu arrives quand même. Joyeux anniversaire, {prenom}.\nAvec admiration pour ta capacité à arriver malgré tout et mystère intact sur comment, — Quelqu'un qui t'a attendu dans beaucoup d'endroits et recommencerait 🗺️` },
    { id: 'sf_g2_06', text: `"Joyeux anniversaire. Tu prends des décisions au dernier moment." Le billet d'avion. La réservation. La réponse à l'invitation. Tout dans les dernières heures. Parfois les dernières minutes. Avec une sérénité qui me fascine et m'exaspère en même temps. Ça se passe toujours bien. Je sais pas comment. Joyeux anniversaire, {prenom}, dernier moment champion.\nAvec fascination persistante pour ton rapport au temps et résultats globalement positifs, — Quelqu'un qui planifie trop et t'envie secrètement un peu 📆` },
    { id: 'sf_g2_07', text: `"Joyeux anniversaire. Tu recommences les mêmes erreurs." Pas toutes. Certaines tu les as réglées. Bravo vraiment. Mais il y en a une ou deux. Spécifiques. Qu'on a analysées ensemble. Sur lesquelles t'as dit c'est bon j'ai compris. Et que t'as recommencées quand même. C'est humain. C'est toi. C'est notre sujet récurrent. Joyeux anniversaire, {prenom}.\nAvec dossier des erreurs récurrentes tenu à jour et absence totale de jugement, — Quelqu'un qui a ses propres erreurs récurrentes et apprécie qu'on n'en parle pas trop 🔄` },
    { id: 'sf_g2_08', text: `"Joyeux anniversaire. Tu changes d'avis." Souvent. Sur des petites choses. Sur des grandes. T'arrives avec une conviction et tu repars avec une autre. C'est soit de la flexibilité intellectuelle soit de l'indécision selon le jour. La plupart du temps c'est de la flexibilité intellectuelle. Parfois c'est de l'indécision. Je fais pas la distinction pour toi. Joyeux anniversaire, {prenom}.\nAvec tolérance totale pour tes revirements et adaptation continue de mon côté, — Quelqu'un qui s'est adapté à tous tes changements d'avis depuis des années 🔀` },
    { id: 'sf_g2_09', text: `"Joyeux anniversaire. Tu parles de toi quand tu demandes comment je vais." T'as une technique. Tu demandes. Je commence à répondre. Et au bout de trente secondes t'as fait le lien avec quelque chose à toi. Et on parle de toi. C'est pas intentionnel. C'est automatique. Et c'est tellement toi que j'ai arrêté d'essayer de finir mes réponses. Joyeux anniversaire, {prenom}.\nAvec adaptation totale à ta technique de conversation et affection pour ce défaut spécifique, — Quelqu'un qui finira sa réponse un jour peut-être 🎤` },
    { id: 'sf_g2_10', text: `"Joyeux anniversaire. Tu es meilleur en intentions qu'en exécution." Les projets que t'as lancés. Les trucs que t'allais faire. Les personnes que t'allais rappeler. Les endroits où on allait aller. Les intentions étaient réelles. L'exécution a été variable. Mais l'intention elle était là et c'est quelque chose. Joyeux anniversaire, {prenom}, grand projet de toi-même.\nAvec respect pour la qualité de tes intentions et paix avec l'exécution variable, — Quelqu'un qui a ses propres projets non exécutés et comprend totalement 💡` },
    { id: 'sf_g2_11', text: `"Joyeux anniversaire. Tu mens sur les horaires." Pas sur les vraies choses. Sur les horaires. Je serai là à 19h. Tu arrives à 19h45. Je serai là dans vingt minutes. Tu arrives dans quarante. J'ai appris à ajouter une marge. Je te donne toujours l'heure réelle moins trente minutes. On s'en sort bien tous les deux. Joyeux anniversaire, {prenom}.\nAvec système de compensation horaire établi et efficacité prouvée sur le long terme, — Quelqu'un qui a son propre décalage et apprécie qu'on soit compatibles 🕐` },
    { id: 'sf_g2_12', text: `"Joyeux anniversaire. T'as des opinions très fortes sur des sujets que tu connais peu." C'est pas un reproche. C'est une observation. T'as une conviction rapide. Une position ferme. Une défense solide. Sur des sujets que tu découvrais il y a quinze jours. C'est du courage intellectuel ou de la précipitation selon l'angle. J'ai choisi l'angle courage. Joyeux anniversaire, {prenom}.\nAvec angle courage choisi délibérément et admiration pour ta vitesse de conviction, — Quelqu'un qui prend plus de temps pour avoir tort et t'envie ce tempo 💬` },
    { id: 'sf_g2_13', text: `"Joyeux anniversaire. Tu gardes des trucs trop longtemps." Des vêtements. Des habitudes. Des rancœurs parfois. Des liens qui auraient dû se terminer. Des convictions dépassées. Cette difficulté à lâcher ce qui a fait son temps. C'est de la fidélité mal placée parfois. C'est de la profondeur aussi. Joyeux anniversaire, {prenom}, gardien de tout.\nAvec analyse nuancée de ton attachement aux choses et tendresse pour ses deux faces, — Quelqu'un que tu gardes aussi depuis longtemps et qui en est reconnaissant 🗂️` },
    { id: 'sf_g2_14', text: `"Joyeux anniversaire. Tu cherches la validation." Pas tout le temps. Mais souvent. T'as fait quelque chose. Tu sais que c'est bien. Et tu attends quand même qu'on le dise. C'est humain. C'est toi. Et moi je le dis. Depuis toujours. Parce que c'est souvent vrai et parce que t'en as besoin et que c'est pas grave d'en avoir besoin. Joyeux anniversaire, {prenom}.\nAvec validation offerte aujourd'hui comme tous les jours, — Quelqu'un qui te dit que c'est bien parce que c'est souvent vrai ✅` },
    { id: 'sf_g2_15', text: `"Joyeux anniversaire. Tu peux pas t'empêcher de donner des conseils." On t'a rien demandé. Tu vois quelque chose. Tu sais comment faire mieux. Et tu le dis. Avec de bonnes intentions. Avec un timing parfois discutable. Avec une assurance que les gens autour n'ont pas toujours demandée. C'est un défaut aimable. Joyeux anniversaire, {prenom}, consultant non mandaté.\nAvec gratitude pour tes conseils dont certains étaient vraiment utiles, — Quelqu'un qui a suivi quelques-uns de tes conseils et ne le dira jamais 📣` },
    { id: 'sf_g2_16', text: `"Joyeux anniversaire. Tu te souviens de ce qui t'arrange." La mémoire est sélective. La tienne particulièrement. Tu te souviens très bien des choses qui prouvent que t'avais raison. Un peu moins bien des choses qui prouvent que t'avais tort. C'est humain. C'est universel. C'est quand même très toi. Joyeux anniversaire, {prenom}.\nAvec mémoire indépendante des faits disponible sur demande, — Quelqu'un qui se souvient de tout et garde ça pour lui par sagesse 🧠` },
    { id: 'sf_g2_17', text: `"Joyeux anniversaire. T'es meilleur pour donner des conseils que pour les suivre." Sur toi-même. Les trucs que tu conseilles aux autres sur leur vie. Les décisions que tu leur recommandes. Les erreurs que tu leur déconseilles. T'as tout ça très clair pour eux. Pour toi c'est plus compliqué. C'est toujours plus compliqué pour soi. Joyeux anniversaire, {prenom}.\nAvec solidarité de quelqu'un dans la même situation exactement, — Quelqu'un qui donne aussi de bons conseils qu'il ne suit pas 🔮` },
    { id: 'sf_g2_18', text: `"Joyeux anniversaire. Tu es trop dur avec toi-même." C'est un défaut aussi. Pas le genre dont on parle habituellement mais c'en est un. Tu t'en demandes trop. Tu te pardonnes moins vite que tu pardonnes aux autres. Tu appliques des standards à toi-même que tu n'appliquerais à personne. C'est épuisant de l'extérieur. Joyeux anniversaire, {prenom}.\nAvec demande officielle de t'accorder la même clémence qu'aux autres, — Quelqu'un qui te voit faire ça depuis longtemps et en a assez de le regarder ⚖️` },
    { id: 'sf_g2_19', text: `"Joyeux anniversaire. Tu commences des trucs et tu finis pas." La liste est longue. On la fait pas ce soir. Mais elle existe. Ces projets en suspens. Ces livres à la page quarante-deux. Ces cours abandonnés. Ces rénovations au stade deux sur cinq. C'est pas un manque de capacité. C'est un problème de routine. Joyeux anniversaire, {prenom}, grand commenceur.\nAvec respect pour tout ce que tu as commencé et curiosité pour ce qui finira, — Quelqu'un qui finit peu de choses aussi et trouve ça très bien comme ça 🏗️` },
    { id: 'sf_g2_20', text: `"Joyeux anniversaire. Avec tous tes défauts tu es quand même ma personne préférée." J'aurais pu faire une liste propre. Des qualités. Des compliments. Quelque chose de beau pour ton anniversaire. J'ai choisi l'honnêteté à la place. Parce qu'on est passés au-delà des compliments polis. Parce que je te connais vraiment. Et que te connaître vraiment c'est t'aimer avec le dossier complet. Joyeux anniversaire, {prenom}.\nAvec dossier complet et verdict sans appel : c'est toi, — Quelqu'un qui t'aime avec tous les éléments du dossier et sans condition ❤️` },
  ],
};

const SF_G3: BirthdaySubGroup = {
  id: 'sf_g3',
  title: 'Tes choix de vie discutables',
  messages: [
    { id: 'sf_g3_01', text: `"Joyeux anniversaire. On va parler de certaines décisions." Pas toutes. Les grandes je les garde pour une autre fois. Juste quelques-unes. Celles qu'on a analysées ensemble à l'époque. Celles sur lesquelles j'avais une opinion que tu n'avais pas demandée. Celles qui se sont avérées exactement comme je l'avais dit. Ou pas. Joyeux anniversaire, {prenom}, grand décideur de ta propre vie.\nAvec bilan des décisions commentées et score approximatif disponible sur demande, — Quelqu'un qui avait raison sur certaines et tort sur d'autres et préfère ne pas compter 📊` },
    { id: 'sf_g3_02', text: `"Joyeux anniversaire. Ce travail que tu as pris alors que tout le monde te déconseillait." T'avais l'air convaincu. On avait l'air sceptique. T'as fait comme tu voulais. C'est bien ou c'est pas bien selon les années. Il y a eu des bonnes années et des moins bonnes. Ce qu'on peut dire c'est que c'était ton choix et que tu l'as fait. Joyeux anniversaire, {prenom}, capitaine de tes propres décisions professionnelles.\nAvec neutralité maintenue sur le bilan et respect pour l'indépendance de la décision, — Quelqu'un qui avait une opinion et qui l'a gardée pour lui après coup 💼` },
    { id: 'sf_g3_03', text: `"Joyeux anniversaire. Cet appartement que tu as loué sans le visiter." Sur photos seulement. Avec cette confiance dans les angles de caméra. Cette certitude que ça allait être bien. Ça l'était pas vraiment. Ou si. Selon comment tu le racontes maintenant. En tout cas tu y as vécu et tu en es sorti. Joyeux anniversaire, {prenom}, aventurier de l'immobilier.\nAvec respect pour ta confiance dans les photos et les leçons éventuellement tirées, — Quelqu'un qui t'a aidé à déménager et qui a une opinion sur le résultat 🏠` },
    { id: 'sf_g3_04', text: `"Joyeux anniversaire. Ce régime dont tu nous as parlé pendant trois semaines." Le nom était compliqué. Les règles aussi. T'avais tout lu. Tout préparé. Tu nous avais expliqué la science derrière. Ça a duré dix jours. Peut-être douze. Puis il y a eu une occasion. Puis une autre. Puis le régime est devenu une anecdote. Joyeux anniversaire, {prenom}.\nAvec archives complètes de tous tes régimes et de leur durée exacte, — Quelqu'un qui t'a écouté chaque fois et continuera d'écouter le prochain 🥗` },
    { id: 'sf_g3_05', text: `"Joyeux anniversaire. Cette formation que tu allais faire." T'en avais parlé. T'avais fait des recherches. T'avais même trouvé l'organisme. T'avais calculé le coût. T'avais réfléchi au timing. Et puis autre chose s'est passé. Et la formation est restée dans un onglet ouvert pendant six mois puis l'onglet s'est fermé. Joyeux anniversaire, {prenom}.\nAvec respect pour la qualité de tes recherches préparatoires et paix avec la suite, — Quelqu'un qui a aussi des onglets ouverts depuis longtemps 💻` },
    { id: 'sf_g3_06', text: `"Joyeux anniversaire. Ce sport que tu allais reprendre." Pas une fois. Plusieurs. À chaque rentrée environ. Parfois au printemps aussi. T'avais des bonnes raisons à chaque fois. Un abonnement pris parfois. Des chaussures achetées. De l'enthousiasme réel. Et puis la vie. Et puis l'abonnement qui expire. Joyeux anniversaire, {prenom}, athlète en potentiel permanent.\nAvec soutien inconditionnel pour la prochaine tentative dont on connaît tous les deux le timing, — Quelqu'un qui a le même abonnement qui expire et trouve ça très bien ainsi 🏋️` },
    { id: 'sf_g3_07', text: `"Joyeux anniversaire. Cette personne que tout le monde te disait d'éviter." On te l'avait dit. Collectivement. Avec des arguments. Avec des exemples. Avec cette solidarité rare où tout le monde était d'accord pour une fois. T'as pas écouté. La suite a varié selon les cas. Mais t'as pas écouté. C'est ton droit. Joyeux anniversaire, {prenom}.\nAvec archives du consensus collectif et neutralité affichée sur la suite des événements, — Quelqu'un qui était dans le consensus et qui n'a pas dit je t'avais prévenu. Presque pas. 🚩` },
    { id: 'sf_g3_08', text: `"Joyeux anniversaire. Ce voyage pas du tout préparé." Billet acheté. Hôtel pas réservé. Plan inexistant. Budget approximatif. Connaissance de la langue nulle. Et pourtant tu y es allé. Et il s'est passé des choses. Bonnes et moins bonnes. Et t'en parles encore. Joyeux anniversaire, {prenom}, voyageur de l'improvisation totale.\nAvec admiration secrète pour ton courage et soulagement de ne pas y avoir participé, — Quelqu'un qui aurait pas survécu à ce niveau d'improvisation ✈️` },
    { id: 'sf_g3_09', text: `"Joyeux anniversaire. Cette période où tu dormais quatre heures par nuit." Tu disais que tu fonctionnais bien comme ça. Tu avais une théorie sur les cycles de sommeil. T'étais convaincu. Les gens autour de toi étaient moins convaincus. Ça a duré quelques mois. T'as rattrapé le sommeil depuis. Joyeux anniversaire, {prenom}, ancien partisan du sommeil minimal.\nAvec soulagement que cette période soit terminée et archive des théories de l'époque, — Quelqu'un qui t'a vu pendant cette période et peut confirmer que ça se voyait 😴` },
    { id: 'sf_g3_10', text: `"Joyeux anniversaire. Cet investissement dont tu nous avais parlé." T'avais fait des recherches. T'avais une stratégie. T'étais sûr. La suite a été variable. Soit t'as eu raison et tu nous le rappelles régulièrement. Soit t'as eu tort et on n'en parle plus jamais et c'est très bien ainsi. Joyeux anniversaire, {prenom}, investisseur courageux.\nAvec mémoire sélective activée selon le résultat et respect dans tous les cas, — Quelqu'un qui a ses propres investissements discutables et préfère changer de sujet 📈` },
    { id: 'sf_g3_11', text: `"Joyeux anniversaire. Cette coupe de cheveux." T'avais une idée. T'avais une photo. T'avais confiance. Le résultat n'était pas tout à fait la photo. T'as géré. T'as porté ça avec plus ou moins de conviction pendant quelques semaines. Ça a repoussé. La vie a continué. Joyeux anniversaire, {prenom}.\nAvec archives photographiques et bienveillance totale sur cette période capillaire, — Quelqu'un qui t'a dit c'est bien quand même et le pensait à moitié ✂️` },
    { id: 'sf_g3_12', text: `"Joyeux anniversaire. Cette fois où t'as changé de vie du jour au lendemain." Tout. Ou presque. En peu de temps. Avec une certitude qui impressionnait et inquiétait en même temps. Certains trucs ont tenu. D'autres moins. L'essentiel c'est que t'es là. Que t'as essayé. Que t'as bougé. Joyeux anniversaire, {prenom}, grand réorganisateur de ta propre existence.\nAvec respect total pour les changements tentés et présence dans tous les réajustements, — Quelqu'un qui t'a suivi dans tous ces changements sans te poser trop de questions 🔄` },
    { id: 'sf_g3_13', text: `"Joyeux anniversaire. Ce projet créatif que tu allais lancer." T'avais un nom. T'avais un concept. T'avais peut-être un logo esquissé. T'avais de l'enthousiasme réel et communicatif. Et puis le quotidien. Et puis le timing pas parfait. Et puis peut-être un jour. Joyeux anniversaire, {prenom}, créateur en attente de lancement.\nAvec conviction que l'idée était bonne et espoir sincère pour le prochain timing parfait, — Quelqu'un qui serait le premier client si ça sort un jour 🎨` },
    { id: 'sf_g3_14', text: `"Joyeux anniversaire. Cette colocation qui allait super bien se passer." T'étais optimiste. L'autre personne aussi probablement. Au début ça allait. Puis les petites choses. Puis les grandes. Puis la fin dans des conditions diverses. T'en as tiré des leçons que tu appliques maintenant ou pas. Joyeux anniversaire, {prenom}.\nAvec solidarité de quelqu'un qui a eu ses propres colocations et comprend les leçons, — Quelqu'un qui t'a écouté pendant toute cette période et s'en souvient très bien 🏠` },
    { id: 'sf_g3_15', text: `"Joyeux anniversaire. Ce moment où t'as dit oui à trop de choses en même temps." T'avais de l'énergie. T'avais confiance en ton agenda. T'avais cette conviction que tout allait rentrer. Et pendant quelques semaines t'as couru. Et t'as tenu. Et puis t'as craqué un peu. Et puis tu t'es réorganisé. Et tu le referas probablement. Joyeux anniversaire, {prenom}.\nAvec admiration pour ton optimisme calendaire et soutien pour les prochaines surcharges, — Quelqu'un qui dit non trop souvent et t'envie parfois sur ce point 📅` },
    { id: 'sf_g3_16', text: `"Joyeux anniversaire. Cette fois où t'as fait confiance trop vite." Pas à moi. À quelqu'un d'autre. T'avais des signaux. On les avait vus ensemble. T'as choisi de faire confiance quand même. C'est une qualité qui coûte parfois. T'en es sorti. T'es là. T'as probablement gardé un peu de cette qualité malgré tout. Joyeux anniversaire, {prenom}.\nAvec respect pour ta capacité à faire confiance et présence dans les fois où ça coûte, — Quelqu'un qui t'a vu traverser ça et était là après 🤝` },
    { id: 'sf_g3_17', text: `"Joyeux anniversaire. Cette opinion que t'as défendue très fort et abandonnée sans commentaire." T'avais raison. Puis les faits ont évolué. Ou ta compréhension. Ou les deux. Et tu as changé de position. Sans cérémonie. Sans annoncer la transition. Un jour t'avais une opinion et le lendemain une autre. C'est de l'intelligence. C'est aussi un peu drôle. Joyeux anniversaire, {prenom}.\nAvec archives de l'ancienne opinion et de la nouvelle et discrétion sur la transition, — Quelqu'un qui a fait pareil et apprécie qu'on n'en parle pas trop 🔄` },
    { id: 'sf_g3_18', text: `"Joyeux anniversaire. Ce déménagement dans une ville où tu connaissais personne." T'avais une raison. Bonne ou moins bonne selon les versions. T'y es allé. C'était difficile au début probablement. Puis t'as trouvé des gens. Puis c'est devenu un endroit. Et maintenant c'est une histoire que tu racontes. Joyeux anniversaire, {prenom}, pionnier de tes propres géographies.\nAvec admiration pour ce type de courage spécifique que tout le monde n'a pas, — Quelqu'un qui t'a manqué pendant cette période et ne l'a pas assez dit 🗺️` },
    { id: 'sf_g3_19', text: `"Joyeux anniversaire. Cette nuit où t'as pris une grande décision." T'étais fatigué. Ou ému. Ou les deux. C'était pas le meilleur moment pour décider. T'as décidé quand même. Et c'était soit la meilleure soit la moins bonne décision selon les jours suivants. En tout cas c'était ta décision. Et t'as vécu avec. Joyeux anniversaire, {prenom}.\nAvec neutralité sur la qualité de la décision et présence dans tout ce qui a suivi, — Quelqu'un qui était là le lendemain matin et a écouté sans juger 🌙` },
    { id: 'sf_g3_20', text: `"Joyeux anniversaire. Avec tous tes choix discutables tu as quand même construit quelque chose." Pas un parcours linéaire. Pas un plan exécuté. Quelque chose de plus irrégulier. De plus humain. Fait de virages et de demi-tours et de surprises. Et au bout c'est toi. Avec tout ça. Et c'est pas si mal. C'est même plutôt bien. Joyeux anniversaire, {prenom}.\nAvec bilan global positif rendu sans complaisance et sincérité totale, — Quelqu'un qui a regardé tout ça de près et confirme que ça tient bien ❤️` },
  ],
};

const SF_G4: BirthdaySubGroup = {
  id: 'sf_g4',
  title: 'Ce qu\'on pense vraiment de tes ex',
  messages: [
    { id: 'sf_g4_01', text: `"Joyeux anniversaire. On peut enfin en parler librement." Pendant que c'était en cours je me taisais. J'avais des opinions. Solides. Documentées. Mais je me taisais parce que c'était ton choix et que mon rôle c'était d'être là. Maintenant c'est fini depuis assez longtemps. Alors joyeux anniversaire, {prenom}, et voilà ce que je pensais vraiment.\nAvec opinions retenues pendant longtemps et libération enfin autorisée, — Quelqu'un qui a beaucoup de choses à dire maintenant que c'est bon 📣` },
    { id: 'sf_g4_02', text: `"Joyeux anniversaire. Le premier. On s'en souvient tous les deux." C'était intense. C'était important à l'époque. C'était aussi un peu catastrophique si on est honnêtes. Mais c'était le premier et les premiers ont une place à part. Ils apprennent des choses. Ils laissent des traces. Ils donnent des références pour la suite. Joyeux anniversaire, {prenom}.\nAvec tendresse pour ce que le premier a représenté et soulagement qu'il soit dans le passé, — Quelqu'un qui était là et qui a les archives complètes de cette période 📼` },
    { id: 'sf_g4_03', text: `"Joyeux anniversaire. Celui ou celle que tout le monde détestait sauf toi." On s'était concertés. Pas officiellement. Mais on avait tous le même avis. On le voyait. T'as mis du temps. Puis t'as vu aussi. Puis c'était fini. Et on a tous fait semblant de pas dire on t'avait prévenu. On l'a dit quand même une fois. Joyeux anniversaire, {prenom}.\nAvec mémoire intacte du consensus collectif et victoire diplomatiquement non célébrée, — Quelqu'un qui était dans le consensus et qui a attendu la bonne occasion pour le dire 🚩` },
    { id: 'sf_g4_04', text: `"Joyeux anniversaire. Celui ou celle qui t'a rendu meilleur." Ça arrive. Pas souvent. Mais ça arrive. Quelqu'un qui passe dans une vie et qui laisse quelque chose de bien. Une habitude. Une façon de voir. Un truc qu'on fait encore sans se souvenir d'où ça vient. Celui-là ou celle-là t'a laissé quelque chose de bien. Joyeux anniversaire, {prenom}.\nAvec reconnaissance pour ce que certaines histoires apportent même quand elles finissent, — Quelqu'un qui a vu le changement que ça a produit et a trouvé ça bien 🌱` },
    { id: 'sf_g4_05', text: `"Joyeux anniversaire. Celui ou celle dont on prononçait plus le prénom." Il y a eu une période. Après la fin. Où le prénom était devenu un mot qu'on évitait. Où il fallait recalibrer la phrase si ça allait arriver. Cette période a duré ce qu'elle a duré. Puis le prénom est redevenu un prénom normal. Joyeux anniversaire, {prenom}.\nAvec mémoire de la période de désintoxication du prénom et soulagement de l'autre côté, — Quelqu'un qui a recalibré beaucoup de phrases pendant cette période 🔇` },
    { id: 'sf_g4_06', text: `"Joyeux anniversaire. Celui ou celle que j'avais adoré au début." Moi aussi j'avais été convaincu. Au début. T'avais l'air tellement bien ensemble. Je leur avais fait confiance. Je m'étais attaché. Puis les choses avaient changé. Et j'avais dû réviser. C'est décevant d'avoir à réviser. Joyeux anniversaire, {prenom}.\nAvec honnêteté sur mon propre enthousiasme initial et déception de la révision, — Quelqu'un qui s'était aussi fait avoir et le prend personnellement 😤` },
    { id: 'sf_g4_07', text: `"Joyeux anniversaire. Celui ou celle qui t'avait changé en moins bien." On t'a vu changer. Pas d'un coup. Progressivement. Tu disais des choses que tu disais pas avant. Tu faisais des choix différents. On s'inquiétait un peu. On a rien dit ou presque. Puis c'est fini et t'es revenu. Joyeux anniversaire, {prenom}, de retour complet.\nAvec soulagement documenté de ton retour à toi-même et silence gardé sur la période, — Quelqu'un qui t'a attendu et est content que tu sois revenu 🏠` },
    { id: 'sf_g4_08', text: `"Joyeux anniversaire. Celui ou celle que t'as quitté et que tu regrettes parfois." Je le sais. T'en parles pas mais je le sais. Ces regrets-là sont les plus compliqués. Pas les regrets des mauvaises histoires. Les regrets des bonnes qui se sont mal terminées. Ou des bonnes qu'on a mal gérées. Joyeux anniversaire, {prenom}.\nAvec espace pour ce regret-là sans jugement et présence si t'as envie d'en parler, — Quelqu'un qui garde le silence sur ça jusqu'à ce que tu veuilles en parler 🤍` },
    { id: 'sf_g4_09', text: `"Joyeux anniversaire. Celui ou celle qui t'a quitté et que tu as mis trop longtemps à oublier." Le délai était trop long selon les observateurs extérieurs. Toi tu avais tes raisons. Tes propres. Que t'expliquais plus ou moins. On t'a écouté autant de fois qu'il le fallait. On a tenu. On est là. Joyeux anniversaire, {prenom}.\nAvec comptage discret des conversations sur ce sujet et endurance prouvée, — Quelqu'un qui a écouté toutes les versions de cette histoire et en connaît chaque détail 🔁` },
    { id: 'sf_g4_10', text: `"Joyeux anniversaire. Celui ou celle dont on sait encore ce qui s'est vraiment passé." T'as ta version. Une version propre. Chronologique. Avec des débuts et des fins claires. Et puis il y a ce qu'on sait. Ce que t'as dit entre les lignes. Ce que les silences racontaient. On a notre version aussi. On la garde. Joyeux anniversaire, {prenom}.\nAvec version complète archivée et discrétion maintenue par choix stratégique, — Quelqu'un qui a entendu les deux versions et sait faire la part des choses 📂` },
    { id: 'sf_g4_11', text: `"Joyeux anniversaire. Celui ou celle qui était trop bien pour être vrai." Et qui l'était effectivement. Trop bien pour être vrai. La façade était impeccable. Le fond l'était moins. Ça a pris du temps à apparaître. Trop de temps peut-être. Mais ça a fini par apparaître. Joyeux anniversaire, {prenom}, survivant des façades impeccables.\nAvec respect pour ce que ce genre d'histoire apprend sur la lecture des gens, — Quelqu'un qui avait des doutes et a attendu que tu les aies aussi 🎭` },
    { id: 'sf_g4_12', text: `"Joyeux anniversaire. Celui ou celle avec qui t'aurais dû rester ami." L'histoire amoureuse avait peut-être pas sa place. Mais quelque chose d'autre aurait pu tenir. Une amitié. Un lien différent. Mieux adapté à ce que vous étiez vraiment l'un pour l'autre. C'est dommage que ça se soit pas fait. Joyeux anniversaire, {prenom}.\nAvec regret sincère pour les bonnes personnes mal catégorisées dans une vie, — Quelqu'un qui pense parfois à ces erreurs de catégorie dans les relations 🤝` },
    { id: 'sf_g4_13', text: `"Joyeux anniversaire. Celui ou celle dont on parle encore parfois." Pas souvent. Mais parfois. Un truc se passe et son nom revient naturellement dans la conversation. Pas avec douleur. Juste comme une référence. Comme quelqu'un qui a existé dans ta vie assez pour rester dans le vocabulaire commun. Joyeux anniversaire, {prenom}.\nAvec constat que certaines personnes restent dans le vocabulaire même après, — Quelqu'un qui sait exactement de qui on parlerait si on continuait cette conversation 💬` },
    { id: 'sf_g4_14', text: `"Joyeux anniversaire. Celui ou celle qui t'a appris ce que tu voulais vraiment." Par contraste. Par comparaison. En te montrant ce que tu ne voulais pas tu as compris ce que tu voulais. C'est une façon inefficace mais efficace d'apprendre. Joyeux anniversaire, {prenom}, diplômé de l'école du contraste.\nAvec respect pour les leçons apprises même par les voies les plus longues, — Quelqu'un qui t'a vu comprendre ce que tu voulais et était content pour toi 🎓` },
    { id: 'sf_g4_15', text: `"Joyeux anniversaire. Tous les autres que j'ai pas mentionnés." Il y en a d'autres. Des petits. Des grands. Des brefs. Des longs. Des compliqués. Des simples. Des dont on a parlé. Des dont on a pas parlé. Ils font partie de qui t'es aujourd'hui. Et qui t'es aujourd'hui c'est plutôt bien. Joyeux anniversaire, {prenom}.\nAvec salutation collective à tous les autres et conclusion sur leur contribution cumulative, — Quelqu'un qui est là maintenant et c'est tout ce qui compte 🎉` },
    { id: 'sf_g4_16', text: `"Joyeux anniversaire. J'ai jamais dit du mal de certains parce que tu les aimais." C'est le contrat. On aime quelqu'un. On se tait sur ce qu'on pense vraiment de leur personne. On est là si ça tourne mal. On reste neutre pendant. C'est de l'amitié. C'est parfois difficile. Joyeux anniversaire, {prenom}, merci de m'avoir épargné les pires.\nAvec comptage des fois où j'ai gardé une opinion pour moi et demande de réciprocité implicite, — Quelqu'un qui a un palmarès de silences diplomatiques dont il est fier 🤐` },
    { id: 'sf_g4_17', text: `"Joyeux anniversaire. T'as un type." Je le vois maintenant. Avec le recul. Une certaine façon d'être. Des traits communs. Pas physiquement forcément. Dans la personnalité. Dans les dynamiques. T'es attiré par les mêmes configurations. C'est fascinant à observer. C'est pas toujours rassurant. Joyeux anniversaire, {prenom}.\nAvec analyse des patterns sur l'ensemble du corpus et rapport disponible si besoin, — Quelqu'un qui voit le type clairement et peut faire un exposé si demandé 🔍` },
    { id: 'sf_g4_18', text: `"Joyeux anniversaire. Le meilleur reste probablement devant." Pas forcément. Peut-être que le meilleur c'était une de ces histoires. Peut-être que le meilleur c'est maintenant. Peut-être que c'est à venir. Je sais pas. Mais l'option que le meilleur soit devant existe vraiment. Et elle mérite d'être nommée le jour de ton anniversaire. Joyeux anniversaire, {prenom}.\nAvec optimisme sincère et pas de garantie mais probabilité réelle, — Quelqu'un qui te souhaite sincèrement ce que tu mérites vraiment 🌅` },
    { id: 'sf_g4_19', text: `"Joyeux anniversaire. T'as survécu à tous." Chacun à sa façon t'a coûté quelque chose. Du temps. De l'énergie. De la confiance parfois. Des nuits. Des conversations. Des versions de toi-même. Et t'es là. Intact en grande partie. Abîmé sur les bords peut-être. Mais là. Joyeux anniversaire, {prenom}, survivant.\nAvec respect pour tout ce que traverser des histoires demande comme endurance, — Quelqu'un qui t'a regardé traverser tout ça et est fier que tu sois là 💪` },
    { id: 'sf_g4_20', text: `"Joyeux anniversaire. Le meilleur dans tout ça c'est que t'as jamais arrêté de faire confiance." Après chaque histoire. Après chaque déception. T'as gardé cette capacité. Faire confiance encore. Essayer encore. Croire que quelque chose de bien est possible encore. C'est du courage. C'est même beaucoup de courage. Joyeux anniversaire, {prenom}.\nAvec admiration sincère pour cette capacité spécifique et rare, — Quelqu'un qui t'admire pour ça plus que pour n'importe quoi d'autre ❤️` },
  ],
};

const SF_G5: BirthdaySubGroup = {
  id: 'sf_g5',
  title: 'Tes habitudes insupportables qu\'on tolère quand même',
  messages: [
    { id: 'sf_g5_01', text: `"Joyeux anniversaire. On va parler de tes habitudes." Pas toutes. Les supportables je les garde pas. Juste les autres. Celles qui font partie du paysage maintenant. Celles qu'on a intégrées. Celles qu'on signale encore parfois par principe mais sans vraiment espérer de changement. Joyeux anniversaire, {prenom}, ensemble de tics affectueux.\nAvec inventaire partiel établi avec amour et résignation mélangés, — Quelqu'un qui s'est adapté à tout ça et en est presque fier 📋` },
    { id: 'sf_g5_02', text: `"Joyeux anniversaire. Tu regardes ton téléphone pendant les films." Pas tout le film. Juste les moments calmes. Et les moments un peu longs. Et les moments où il se passe quelque chose d'important mais que t'avais pas prévu. Et parfois les moments d'action aussi. En gros tu regardes ton téléphone pendant les films. Joyeux anniversaire, {prenom}.\nAvec statistiques personnelles estimées à environ quarante pour cent d'attention réelle, — Quelqu'un qui te raconte ce que t'as manqué depuis des années et continuera 📱` },
    { id: 'sf_g5_03', text: `"Joyeux anniversaire. Tu spoiles." Involontairement. Toujours involontairement. T'as pas fait exprès. T'avais oublié que j'avais pas vu. T'étais tellement enthousiaste que t'as pas pensé. C'est arrivé suffisamment de fois pour constituer un pattern. J'ai arrêté de te dire ce que je regarde. Joyeux anniversaire, {prenom}.\nAvec liste des spoilers reçus au fil des années et adaptation de ma stratégie d'information, — Quelqu'un qui garde ses projets de visionnage secrets maintenant et c'est plus simple 🎬` },
    { id: 'sf_g5_04', text: `"Joyeux anniversaire. Tu poses des questions pendant les films." Qui c'est lui. Elle était pas là avant. C'est quoi le rapport avec l'autre truc. Attends je comprends pas. Ces questions posées à voix haute pendant que le film essaie de répondre à ces questions. Si on écoutait le film on aurait les réponses. Joyeux anniversaire, {prenom}.\nAvec patience développée sur de nombreuses années et technique de réponse minimale maîtrisée, — Quelqu'un qui répond en murmurant depuis si longtemps que c'est devenu automatique 🎥` },
    { id: 'sf_g5_05', text: `"Joyeux anniversaire. Tu arrives avec de la nourriture non planifiée." C'est gentil. Vraiment. L'intention est parfaite. Mais tu arrives avec quelque chose à manger alors que le repas est prévu. Ou que j'ai déjà mangé. Ou que c'est incompatible avec ce qu'il y a. Et je mange quand même parce que c'est gentil. Joyeux anniversaire, {prenom}, porteur de nourriture surprise.\nAvec gratitude sincère pour l'intention et adaptation digestive en conséquence, — Quelqu'un qui a toujours de la place pour ta nourriture surprise et en est content 🍕` },
    { id: 'sf_g5_06', text: `"Joyeux anniversaire. Tu réponds aux messages quand tu en as envie." Pas quand ils arrivent. Pas forcément le même jour. Parfois plusieurs jours après. Avec une réponse enthousiaste qui dit rien sur le délai. Comme si le message venait d'arriver. J'ai calibré mes attentes. Je sais que tu réponds. Je sais juste pas quand. Joyeux anniversaire, {prenom}.\nAvec attentes calibrées sur de nombreuses années et soulagement à chaque réponse, — Quelqu'un qui t'envoie des messages sans attendre de réponse rapide depuis longtemps 📩` },
    { id: 'sf_g5_07', text: `"Joyeux anniversaire. Tu fais du bruit en mangeant certaines choses." Des choses croquantes surtout. T'es pas conscient. C'est automatique. C'est corporel. C'est toi. J'ai appris à pas manger des choses croquantes en même temps que toi pour éviter la superposition. On a trouvé notre rythme. Joyeux anniversaire, {prenom}.\nAvec adaptation acoustique développée et rythme de repas synchronisé en conséquence, — Quelqu'un qui a ses propres bruits de repas et préfère ne pas comparer 🥨` },
    { id: 'sf_g5_08', text: `"Joyeux anniversaire. Tu laisses les placards ouverts." Pas un peu ouverts. Grands ouverts. Comme si tu avais l'intention de revenir dans la seconde. Et puis tu pars dans une autre pièce. Et les placards restent ouverts. Et moi je les ferme. Depuis des années je ferme tes placards. C'est mon rôle maintenant. Joyeux anniversaire, {prenom}.\nAvec comptage approximatif des placards fermés au fil du temps et acceptation du rôle, — Quelqu'un qui ferme tes placards depuis si longtemps que c'est une identité 🚪` },
    { id: 'sf_g5_09', text: `"Joyeux anniversaire. Tu recommences une série qu'on regardait ensemble." Sans moi. De ton côté. Parce que t'avais envie. Parce que t'avais oublié où on en était. Parce que t'avais pas de patience. Et quand on se retrouve t'es plusieurs épisodes devant. Et tu fais semblant d'avoir oublié ce qui se passe. Joyeux anniversaire, {prenom}.\nAvec preuve que tu savais exactement ce qui se passait et archives des regards suspects, — Quelqu'un qui sait que tu avais vu et qui regarde quand même avec toi 📺` },
    { id: 'sf_g5_10', text: `"Joyeux anniversaire. Tu chantes les paroles que tu connais pas." T'inventes. Avec conviction. Avec le même rythme que les vraies paroles. Avec une confiance qui dit que personne va vérifier. Parfois t'es à côté de façon spectaculaire. Parfois c'est presque juste. T'arrêtes jamais de chanter pour cette raison. Joyeux anniversaire, {prenom}.\nAvec admiration pour ta confiance vocale et collection des meilleures inventions de paroles, — Quelqu'un qui chante aussi les mauvaises paroles mais moins fort 🎵` },
    { id: 'sf_g5_11', text: `"Joyeux anniversaire. Tu laisses des notifications partout." Des milliers. Sur toutes les applis. T'es pas dérangé par ça. Moi si. Je regarde ton téléphone par accident parfois et j'ai une réaction physique. Comment tu vis avec ça. Comment c'est possible. Joyeux anniversaire, {prenom}, collectionneur de notifications non lues.\nAvec incompréhension totale et respect pour ta sérénité face au rouge partout, — Quelqu'un qui a zéro notification et trouve les deux modes de vie également valables 🔴` },
    { id: 'sf_g5_12', text: `"Joyeux anniversaire. Tu ne lis pas les modes d'emploi." Jamais. Ou presque jamais. T'essaies directement. T'improvises. T'as confiance en ton instinct. Parfois ça marche. Parfois ça prend trois fois plus de temps que si t'avais lu. Parfois il faut recommencer. T'as pas changé là-dessus. Joyeux anniversaire, {prenom}.\nAvec observation de tes montages hasardeux et aide discrète apportée après les premières tentatives, — Quelqu'un qui lit les modes d'emploi en secret pour pouvoir intervenir au bon moment 📖` },
    { id: 'sf_g5_13', text: `"Joyeux anniversaire. Tu dis deux secondes et c'est jamais deux secondes." Deux secondes c'est entre cinq minutes et un quart d'heure selon les contextes. J'ai établi la table de conversion. Je l'applique automatiquement maintenant. Quand tu dis deux secondes j'installe confortablement et je prends quelque chose à lire. Joyeux anniversaire, {prenom}.\nAvec table de conversion des deux secondes affichée mentalement en permanence, — Quelqu'un qui a arrêté d'attendre debout depuis longtemps ⏱️` },
    { id: 'sf_g5_14', text: `"Joyeux anniversaire. Tu perds tes affaires." Les clés surtout. Mais pas seulement. Régulièrement. Avec une régularité qui suggère que c'est structural et pas accidentel. T'as des systèmes. Les systèmes échouent. Tu cherches. Tu trouves. Tu perds à nouveau. C'est le cycle. Joyeux anniversaire, {prenom}.\nAvec participation au cycle de recherche depuis des années et localisation intuitive développée, — Quelqu'un qui sait souvent où sont tes affaires avant que tu cherches 🔑` },
    { id: 'sf_g5_15', text: `"Joyeux anniversaire. Tu interromps." Pas méchamment. Avec enthousiasme. T'as quelque chose à dire qui est lié et t'attends pas que j'aie fini. Parce que ta pensée va partir si tu attends. Parce que le lien va disparaître. Je comprends. J'ai adapté mes phrases pour être plus courtes. Joyeux anniversaire, {prenom}.\nAvec adaptation syntaxique de mes phrases sur de nombreuses années et résultats mitigés, — Quelqu'un qui t'interrompt aussi parfois et préfère ne pas calculer le score 💬` },
    { id: 'sf_g5_16', text: `"Joyeux anniversaire. Tu poses des questions dont tu connais déjà la réponse." Pour confirmer. Pour entendre la réponse dite à voix haute. Pour t'assurer que tout le monde est sur la même page. C'est une façon de communiquer. C'est parfois légèrement redondant. C'est très toi. Joyeux anniversaire, {prenom}.\nAvec réponse préparée aux questions dont la réponse est connue depuis des années, — Quelqu'un qui répond quand même chaque fois avec la même patience 🔁` },
    { id: 'sf_g5_17', text: `"Joyeux anniversaire. Tu t'endors dans les transports." Toujours. Train. Voiture. Parfois bus. Peu importe l'heure. Peu importe si t'as dormi. Le mouvement déclenche quelque chose. T'es endormi en cinq minutes. Et moi je surveille ton arrêt ou ton terminal. Depuis des années je surveille. Joyeux anniversaire, {prenom}.\nAvec rôle de garde-sommeil assumé dans tous les transports partagés, — Quelqu'un qui t'a réveillé à temps suffisamment souvent pour que ça compte 🚆` },
    { id: 'sf_g5_18', text: `"Joyeux anniversaire. Tu finis les phrases des autres." Parfois correctement. Parfois pas. Avec la même assurance dans les deux cas. Comme si finir la phrase de quelqu'un était un service rendu. Parfois c'en est un. Parfois c'est juste interrompre élégamment. Joyeux anniversaire, {prenom}.\nAvec statistiques personnelles sur le taux de fins de phrases correctes et résultat acceptable, — Quelqu'un dont tu finis aussi les phrases et qui trouve ça finalement sympa 💭` },
    { id: 'sf_g5_19', text: `"Joyeux anniversaire. Tu poses ton téléphone sur la table en réunion ou au restaurant." Face vers le haut. Pour voir si ça vibre. Tout en étant présent. Tout en écoutant. Juste au cas où. Cette présence parallèle. Ce fil tendu vers une autre conversation possible. Joyeux anniversaire, {prenom}, multitâche affectif.\nAvec observation de ce tic spécifique et paix avec son existence permanente, — Quelqu'un qui fait pareil et trouve qu'on se ressemble sur ce point précis 📲` },
    { id: 'sf_g5_20', text: `"Joyeux anniversaire. Avec toutes ces habitudes t'es quand même la personne que je choisirais." Si on me donnait une liste. Avec tous les défauts dedans. Et qu'on me demandait de choisir. Je choisirais quand même toi. Parce que je connais exactement ce que je prends. Parce que c'est confortable de connaître vraiment quelqu'un. Parce que t'es toi et que c'est suffisant. Joyeux anniversaire, {prenom}.\nAvec choix délibéré et conscient renouvelé aujourd'hui, — Quelqu'un qui te choisit avec le dossier complet depuis longtemps ❤️` },
  ],
};

const SF_G6: BirthdaySubGroup = {
  id: 'sf_g6',
  title: 'Ce que tu mérites vraiment comme cadeau',
  messages: [
    { id: 'sf_g6_01', text: `"Joyeux anniversaire. J'ai réfléchi à ce que tu mérites vraiment." Pas ce qu'on offre habituellement. Ce qu'il te faudrait vraiment. Ce qui changerait quelque chose. Ce qui répondrait à un vrai besoin. J'ai fait la liste. Elle est surprenante. Elle est honnête. Elle dit des choses sur toi que tu sais déjà. Joyeux anniversaire, {prenom}, voilà ce que tu mérites vraiment.\nAvec liste établie après réflexion sérieuse et honnêteté totale sur les besoins réels, — Quelqu'un qui te connaît assez pour savoir ce qui t'aiderait vraiment 🎁` },
    { id: 'sf_g6_02', text: `"Joyeux anniversaire. Tu mérites une journée sans prendre de décisions." Pas une seule. Quelqu'un d'autre décide de tout. Où on mange. À quelle heure. Quoi faire après. Dans quel ordre. Toi tu suis. Tu existes. Tu profites. Sans le poids de décider quoi que ce soit pendant vingt-quatre heures. Joyeux anniversaire, {prenom}.\nAvec compréhension de ce que ce cadeau représenterait vraiment pour toi, — Quelqu'un qui serait prêt à décider tout à ta place pour une journée entière 📋` },
    { id: 'sf_g6_03', text: `"Joyeux anniversaire. Tu mérites quelqu'un qui répond à tes messages rapidement." Pas dans trois jours. Pas quand l'autre en a envie. Rapidement. Parce que tu mérites d'être prioritaire. Parce que tu réponds toi-même rapidement et que la réciprocité devrait exister. Ce cadeau-là coûte rien et vaut tout. Joyeux anniversaire, {prenom}.\nAvec conscience que je suis parfois coupable de ce délit et résolution de faire mieux, — Quelqu'un qui va répondre plus vite maintenant à titre de cadeau d'anniversaire 📱` },
    { id: 'sf_g6_04', text: `"Joyeux anniversaire. Tu mérites une nuit de sommeil complète sans réveil." Pas d'alarme. Pas de bruit extérieur. Pas de chose à laquelle tu penses à 3h du matin. Pas de réveil préventif pour pas rater quelque chose. Juste dormir jusqu'à ce que le corps décide que c'est fini. Ce luxe absolu. Joyeux anniversaire, {prenom}.\nAvec conscience que ce cadeau est peut-être le plus précieux de la liste, — Quelqu'un qui te souhaite au moins une nuit comme ça cette année 🛏️` },
    { id: 'sf_g6_05', text: `"Joyeux anniversaire. Tu mérites que quelqu'un règle ce truc administratif à ta place." Ce truc. Tu sais lequel. Celui qui traîne. Celui que t'as reporté. Celui qui demande un appel téléphonique ou un formulaire ou les deux. Celui qui est dans un coin de ta tête depuis trop longtemps. Quelqu'un devrait le régler pour toi. Joyeux anniversaire, {prenom}.\nAvec offre implicite d'aide si tu me dis quel truc c'est, — Quelqu'un qui déteste aussi l'administratif mais pourrait faire une exception pour toi 📄` },
    { id: 'sf_g6_06', text: `"Joyeux anniversaire. Tu mérites une semaine sans que personne te demande quelque chose." Pas une demande. Pas un service. Pas une opinion. Pas une disponibilité. Pas un est-ce que tu peux. Juste exister sans être une ressource pour les autres pendant sept jours. Ce cadeau invisible et révolutionnaire. Joyeux anniversaire, {prenom}.\nAvec conscience de combien tu donnes aux autres et de combien c'est épuisant, — Quelqu'un qui essaiera de ne rien te demander cette semaine en guise de cadeau 🤲` },
    { id: 'sf_g6_07', text: `"Joyeux anniversaire. Tu mérites qu'on te dise que t'as raison sans que tu aies à plaider ton dossier." Parfois tu sais. Depuis le début tu sais. Et tu dois quand même expliquer. Argumenter. Convaincre. Défendre. Alors que t'avais raison depuis le début. Ce cadeau-là c'est qu'on te dise t'as raison directement. Sans procès. Joyeux anniversaire, {prenom}.\nAvec reconnaissance que ça arrive trop rarement et promesse d'y remédier, — Quelqu'un qui dit t'as raison aujourd'hui sans demander les arguments ✅` },
    { id: 'sf_g6_08', text: `"Joyeux anniversaire. Tu mérites un ami qui arrive à l'heure." Pas en avance. Pas en retard. À l'heure. Exactement quand c'était prévu. Sans message d'excuse. Sans dix minutes de marge. À l'heure. Je sais que c'est pas toujours mon fort. Je sais que tu mérites mieux sur ce point. Joyeux anniversaire, {prenom}.\nAvec aveu honnête de mon propre bilan de ponctualité et résolution sincère, — Quelqu'un qui sera à l'heure aujourd'hui au moins comme cadeau symbolique ⏰` },
    { id: 'sf_g6_09', text: `"Joyeux anniversaire. Tu mérites que quelqu'un remarque les petites choses que tu fais." Ces gestes. Ces attentions. Ces choses que tu fais silencieusement pour que tout aille bien. Que les autres n'ont pas à remarquer parce que ça marche. Que personne ne remarque justement parce que ça marche. Quelqu'un devrait les voir. Joyeux anniversaire, {prenom}, je les vois.\nAvec liste mentale de tous les petits gestes observés et non nommés jusqu'ici, — Quelqu'un qui les a tous vus et choisit aujourd'hui de le dire 👁️` },
    { id: 'sf_g6_10', text: `"Joyeux anniversaire. Tu mérites une conversation qui va vraiment au fond des choses." Pas une conversation normale. Une vraie. Longue. Qui part dans toutes les directions. Qui revient. Qui creuse. Qui finit tard. Celle qu'on a pas souvent parce que la vie va vite. Celle qui laisse quelque chose après. Joyeux anniversaire, {prenom}.\nAvec disponibilité réelle pour cette conversation quand tu veux, — Quelqu'un qui est prêt pour cette conversation ce soir si t'as le temps 💬` },
    { id: 'sf_g6_11', text: `"Joyeux anniversaire. Tu mérites que quelqu'un cuisine pour toi." Pas commander. Pas réchauffer. Cuisiner. Avec du soin. Pour toi spécifiquement. Ce que tu aimes. Comme tu l'aimes. Servi sans que tu aies à t'occuper de quoi que ce soit. Juste toi et quelqu'un qui a pensé à ce qui te ferait plaisir. Joyeux anniversaire, {prenom}.\nAvec offre sincère si l'occasion se présente, — Quelqu'un qui cuisine pas si mal et pourrait faire ça pour toi 🍳` },
    { id: 'sf_g6_12', text: `"Joyeux anniversaire. Tu mérites qu'on te laisse choisir le restaurant sans débat." Pas de peut-être. Pas de oh mais l'autre aussi c'est bien. Pas de t'es sûr. Toi tu choisis. Tout le monde dit super. On y va. Sans négociation. Sans compromis. Sans réunion de consensus. Joyeux anniversaire, {prenom}, dictateur culinaire d'un soir.\nAvec délégation totale du pouvoir gastronomique pour ce soir, — Quelqu'un qui ira où tu veux sans commentaire ce soir 🍽️` },
    { id: 'sf_g6_13', text: `"Joyeux anniversaire. Tu mérites une journée sans regarder ton téléphone." Une vraie. Complète. Sans vérifier. Sans répondre. Sans être disponible. Juste toi et le monde réel pendant vingt-quatre heures. Ce cadeau terrifiant et libérateur. Ce luxe devenu presque impossible. Joyeux anniversaire, {prenom}.\nAvec conscience que c'est difficile et admiration si tu essaies vraiment, — Quelqu'un qui essaiera aussi un jour et reporte ça depuis des années 📵` },
    { id: 'sf_g6_14', text: `"Joyeux anniversaire. Tu mérites que quelqu'un t'écoute jusqu'au bout sans parler de lui." Toute l'histoire. Jusqu'à la fin. Sans que la conversation parte sur l'autre. Sans que la réponse soit une anecdote similaire sur quelqu'un d'autre. Juste toi. Juste ton truc. Jusqu'au bout. Joyeux anniversaire, {prenom}.\nAvec engagement de faire exactement ça aujourd'hui si tu as quelque chose à dire, — Quelqu'un qui t'écoute jusqu'au bout aujourd'hui et garde ses anecdotes pour demain 👂` },
    { id: 'sf_g6_15', text: `"Joyeux anniversaire. Tu mérites une vraie surprise." Pas une fausse surprise où tu sais à peu près. Une vraie. Quelque chose que t'avais pas imaginé. Qui vient de quelqu'un qui te connaît assez pour trouver quelque chose que t'aurais pas trouvé toi-même. Ce cadeau rare. Joyeux anniversaire, {prenom}.\nAvec conscience que les vraies surprises sont rares et méritent d'être tentées plus souvent, — Quelqu'un qui prépare peut-être quelque chose que tu n'attends pas 🎭` },
    { id: 'sf_g6_16', text: `"Joyeux anniversaire. Tu mérites qu'on arrête de te demander si t'as rencontré quelqu'un." Si c'est le cas dans ta vie en ce moment. Cette question. Répétée. Avec de bonnes intentions et un effet désastreux. Quelqu'un devrait distribuer un mémo. Joyeux anniversaire, {prenom}, affranchi de cette question pour aujourd'hui au moins.\nAvec promesse formelle de ne pas poser cette question aujourd'hui, — Quelqu'un qui a compris que si t'avais quelque chose à dire tu le dirais 🙅` },
    { id: 'sf_g6_17', text: `"Joyeux anniversaire. Tu mérites un après-midi entier à ne rien faire sans culpabilité." Pas de productivité. Pas de tâches. Pas de trucs qu'on aurait pu faire pendant ce temps. Juste ne rien faire. Complètement. Avec la conscience tranquille que c'est exactement ce qu'il fallait faire. Ce cadeau que tu t'accordes rarement. Joyeux anniversaire, {prenom}.\nAvec permission officielle accordée pour cet après-midi, — Quelqu'un qui signe l'autorisation de ne rien faire dès aujourd'hui 🛋️` },
    { id: 'sf_g6_18', text: `"Joyeux anniversaire. Tu mérites que quelqu'un te dise merci pour un truc spécifique." Pas merci en général. Merci pour ce truc précis. Ce moment précis. Ce geste précis. Que tu te souviens peut-être pas avoir fait. Ou que tu as fait il y a longtemps. Ou que tu fais tout le temps sans que personne le nomme. Joyeux anniversaire, {prenom}.\nAvec merci spécifique à suivre pour quelque chose de réel que tu as fait, — Quelqu'un qui a quelque chose de précis à te dire merci et va le faire aujourd'hui 🙏` },
    { id: 'sf_g6_19', text: `"Joyeux anniversaire. Tu mérites d'être aussi gentil avec toi-même qu'avec les autres." Ce standard. Que t'appliques aux autres naturellement. Cette bienveillance. Ce bénéfice du doute. Cette façon de comprendre les erreurs des autres. T'en as besoin pour toi aussi. Exactement pareil. Joyeux anniversaire, {prenom}.\nAvec demande formelle de réciprocité dans ta gentillesse, — Quelqu'un qui te regarde être dur avec toi-même depuis trop longtemps et en a assez ⚖️` },
    { id: 'sf_g6_20', text: `"Joyeux anniversaire. Tu mérites exactement ce soir." Ces gens. Cet endroit. Ces conversations. Ce moment. T'as travaillé pour ça. T'as construit ça. Ces gens sont là parce que tu mérites qu'ils soient là. Ce soir c'est exactement ce que tu mérites. Rien de plus imaginaire. Rien de moins. Juste ça. Joyeux anniversaire, {prenom}.\nAvec certitude absolue que ce soir est à la hauteur de ce que tu mérites, — Quelqu'un qui est là ce soir et nulle part ailleurs ❤️` },
  ],
};

