const EX_G1: BirthdaySubGroup = {
  id: 'ex_g1',
  title: 'Drôle et décalé',
  messages: [
    { id: 'ex_g1_01', text: `"Joyeux anniversaire. On a survécu l'un à l'autre." C'est déjà quelque chose. Statistiquement. Humainement. Émotionnellement. Survivre à une relation c'est pas rien. On l'a fait tous les deux. On est là. On va bien. C'est une victoire. Joyeux anniversaire, {prenom}.\nAvec célébration de notre survie mutuelle et respect pour les deux rescapés, — Quelqu'un qui célèbre cette victoire sans en faire trop 🏆` },
    { id: 'ex_g1_02', text: `"Joyeux anniversaire. J'ai retrouvé une de tes affaires." Après tout ce temps. Dans un tiroir. Sous quelque chose. Dans un endroit improbable. Cette chose qui n'a pas eu la décence de disparaître avec le reste. Cette réapparition tardive et malvenue. Joyeux anniversaire, {prenom}.\nAvec incertitude totale sur quoi faire de ladite affaire, — Quelqu'un qui ne sait pas encore si c'est un signe ou juste un fond de tiroir 🗄️` },
    { id: 'ex_g1_03', text: `"Joyeux anniversaire. J'ai pensé à toi parce que j'ai entendu cette chanson." Celle-là. Tu sais laquelle. Celle qu'on ne peut plus écouter sans penser à quelque chose. Ce conditionnement musical qui dure des années. Cette association pavlovienne entre une mélodie et un souvenir. Joyeux anniversaire, {prenom}.\nAvec résignation face au conditionnement musical qui refuse de partir, — Quelqu'un qui changera de station la prochaine fois probablement 🎵` },
    { id: 'ex_g1_04', text: `"Joyeux anniversaire. J'ai regardé notre conversation d'il y a trois ans par accident." En cherchant autre chose. Et je suis tombé dessus. Et j'ai lu. Avec ce mélange particulier d'amusement et de quelque chose d'autre. Ces messages. Ces choses qu'on disait. Cette façon qu'on avait. C'était quelque chose. Joyeux anniversaire, {prenom}.\nAvec rapport d'une fouille d'archive non intentionnelle et émotions diverses, — Quelqu'un qui a refermé ça assez vite et préfère ne pas quantifier le temps passé à lire 📱` },
    { id: 'ex_g1_05', text: `"Joyeux anniversaire. Je vois qu'il t'arrive des choses." Les réseaux sociaux. Cette fenêtre sur la vie des gens. Ces informations non demandées. Ces mises à jour automatiques. Cette façon de continuer à savoir sans vraiment chercher. Joyeux anniversaire, {prenom}.\nAvec honnêteté sur l'existence de cette fenêtre et discrétion sur ce qu'on y voit, — Quelqu'un qui a les infos sans avoir cherché et préfère ne pas préciser 👀` },
    { id: 'ex_g1_06', text: `"Joyeux anniversaire. J'ai failli t'envoyer quelque chose de drôle." Un truc qui t'aurait fait rire. Que t'aurais compris. Qui aurait eu du sens pour toi spécifiquement. Et puis j'ai hésité. Et la fenêtre d'envoi s'est fermée. Et je suis resté là avec mon truc drôle et personne à qui l'envoyer. Joyeux anniversaire, {prenom}.\nAvec frustration d'avoir un contenu parfaitement adapté et personne à qui l'envoyer, — Quelqu'un qui a un stock de trucs qu'il aurait pu t'envoyer et garde ça pour lui 😄` },
    { id: 'ex_g1_07', text: `"Joyeux anniversaire. On avait des projets qu'on a jamais faits." La liste. Ces endroits où on allait aller. Ces choses qu'on allait faire. Ces projets qui avaient une durée de vie limitée par la relation. Certains je les ai faits avec quelqu'un d'autre. Certains attendent encore. Joyeux anniversaire, {prenom}.\nAvec inventaire partiel des projets abandonnés et bilan mitigé, — Quelqu'un qui est allé à cet endroit finalement avec quelqu'un d'autre et c'était bien aussi ✈️` },
    { id: 'ex_g1_08', text: `"Joyeux anniversaire. J'ai dû réapprendre à dormir de mon côté." Ça prend du temps. Cette réorganisation spatiale. Ce retour à une topographie nocturne différente. Cette négociation avec le matelas. Ces semaines bizarres. Joyeux anniversaire, {prenom}, j'ai réussi éventuellement.\nAvec bilan final positif sur la récupération de l'espace nocturne, — Quelqu'un qui a toute la place maintenant et alterne entre trouver ça bien et moins bien 🛏️` },
    { id: 'ex_g1_09', text: `"Joyeux anniversaire. Je sais plus exactement comment te présenter aux gens." Mon ex. Ma connaissance. Quelqu'un que j'ai connu. Quelqu'un d'important à une époque. Cette question de nomenclature. Ces catégories insuffisantes. Ces explications qui demandent plus de contexte qu'on veut en donner. Joyeux anniversaire, {prenom}.\nAvec problème de catégorisation non résolu et approche au cas par cas maintenue, — Quelqu'un qui improvise encore la présentation selon l'audience 🏷️` },
    { id: 'ex_g1_10', text: `"Joyeux anniversaire. T'es resté dans certaines anecdotes." Ces histoires que je raconte. Qui incluent quelqu'un sans le nommer. Ou avec un un ami ou une connaissance. Ces versions éditorisées de nos histoires communes. T'es encore là dedans. Anonymisé mais présent. Joyeux anniversaire, {prenom}.\nAvec confirmation que tu fais partie du répertoire d'anecdotes sous couverture, — Quelqu'un dont les meilleures anecdotes impliquent encore des personnages non nommés 🎭` },
    { id: 'ex_g1_11', text: `"Joyeux anniversaire. J'ai réappris à aimer certaines choses que t'aimais pas." Ces trucs. Que tu trouvais pas bien. Que j'avais mis de côté. Consciemment ou pas. Et qui sont revenus. Avec un plaisir légèrement amplifié peut-être. Joyeux anniversaire, {prenom}.\nAvec réhabilitation complète des trucs mis de côté pendant la relation, — Quelqu'un qui mange à nouveau ce que tu aimais pas sans aucune culpabilité 🍕` },
    { id: 'ex_g1_12', text: `"Joyeux anniversaire. Le codex de nos blagues est expiré." Ces références. Ces codes. Ces trucs qu'on trouvait drôles. Certains ont une durée de vie liée à la relation. Ils sont là. Ils fonctionnent encore techniquement. Mais sans l'autre le contexte est bizarre. Joyeux anniversaire, {prenom}.\nAvec constat de l'expiration partielle du codex et efforts de mise à jour en cours, — Quelqu'un qui a recyclé certaines blagues avec un nouveau public sans trop de remords 😄` },
    { id: 'ex_g1_13', text: `"Joyeux anniversaire. J'ai retrouvé mon rythme." Pas immédiatement. Ça prend le temps que ça prend. Mais maintenant j'ai mon rythme. Mes habitudes à moi. Mon organisation. Mon chaos organisé. Ma façon de faire les choses quand personne négocie avec moi. Joyeux anniversaire, {prenom}.\nAvec rapport de reconquête du rythme personnel et satisfaction modérée, — Quelqu'un qui fait les choses dans son ordre et le trouve parfait 🔄` },
    { id: 'ex_g1_14', text: `"Joyeux anniversaire. On aurait pas dû regarder cette série ensemble." Parce que maintenant elle est compromise. Elle appartient à une période. Elle a des associations. La finir avec quelqu'un d'autre est compliqué. La finir seul aussi. La laisser en plan est frustrant. Joyeux anniversaire, {prenom}, tu m'as compliqué mon rapport à cette série.\nAvec grief spécifique sur la série compromise et absence de solution en vue, — Quelqu'un qui a finalement regardé la fin tout seul et c'était bittersweet 📺` },
    { id: 'ex_g1_15', text: `"Joyeux anniversaire. Certaines de tes habitudes ont déteint." Sans le chercher. Ces petits trucs. Ces façons de faire. Ces mots. Ces gestes. Ces préférences. Qui venaient de toi et qui sont restés. Ces souvenirs incorporés. Ces traces dans les comportements. Joyeux anniversaire, {prenom}, tu hantes mes habitudes.\nAvec inventaire partiel des habitudes héritées et acceptation de leur présence permanente, — Quelqu'un qui fait des trucs qui viennent de toi sans s'en souvenir à chaque fois 👻` },
    { id: 'ex_g1_16', text: `"Joyeux anniversaire. J'ai recalibré mes standards." Dans les deux sens selon les domaines. Pour certaines choses tu m'avais habitué à bien. Pour d'autres moins bien. Le recalibrage a pris du temps. Il est fait maintenant. Joyeux anniversaire, {prenom}, référence de calibrage.\nAvec bilan du recalibrage complet et standards actuels jugés satisfaisants, — Quelqu'un dont les standards sont maintenant exactement là où ils devraient être 📏` },
    { id: 'ex_g1_17', text: `"Joyeux anniversaire. On a eu des discussions qui n'avaient pas de sens." Ces disputes sur des trucs minuscules. Ces désaccords sur des questions sans importance. Ces heures passées à débattre de choses qui n'existaient que dans notre espace. Cette énergie. Ces enjeux imaginaires. Joyeux anniversaire, {prenom}.\nAvec recul total sur la teneur de certaines de ces discussions, — Quelqu'un qui a débattu avec toi de choses dont il se souvient plus et qui trouve ça drôle maintenant 💬` },
    { id: 'ex_g1_18', text: `"Joyeux anniversaire. Tu m'as laissé avec certaines de tes opinions." Sur des sujets. Des positions que j'ai adoptées. Des façons de voir des choses. Qui venaient de toi au départ. Et qui sont miennes maintenant. T'es parti mais certaines de tes convictions sont restées. Joyeux anniversaire, {prenom}, colonisateur d'opinions.\nAvec inventaire des opinions héritées et évaluation de leur qualité variable, — Quelqu'un dont certaines opinions ont été améliorées par toi et d'autres sont à retravailler 🧠` },
    { id: 'ex_g1_19', text: `"Joyeux anniversaire. On était pas faits pour ça mais on était faits pour quelque chose." Peut-être pas pour durer. Peut-être pas pour être ça jusqu'à la fin. Mais pour cette période. Pour ces leçons. Pour ces moments. Pour ce que ça a apporté à chacun. Pour ça oui. Joyeux anniversaire, {prenom}.\nAvec paix sur ce pour quoi on était faits et sur ce pour quoi on ne l'était pas, — Quelqu'un qui a trouvé la paix avec cette distinction et la trouve juste 🌿` },
    { id: 'ex_g1_20', text: `"Joyeux anniversaire. Ça valait le coup quand même." Avec tout. Avec les difficultés et les fins et ce qui a coûté. Ça valait le coup. Les bons moments valaient. Les leçons valaient. La présence valait. Le tout valait. Joyeux anniversaire, {prenom}.\nAvec bilan final positif rendu honnêtement, — Quelqu'un qui pense que ça valait le coup et assume ce jugement 💛` },
  ],
};

const EX_G2: BirthdaySubGroup = {
  id: 'ex_g2',
  title: 'Nostalgique et doux',
  messages: [
    { id: 'ex_g2_01', text: `"Joyeux anniversaire. Ton rire me manque." Cette façon précise. Ce son. Cette expression. Ces choses qu'on remarque des gens qu'on a aimés. Qui restent dans la mémoire. Qui font quelque chose quand on y pense. Joyeux anniversaire, {prenom}.\nAvec douceur pour ce souvenir précis et pour ce qu'il représente, — Quelqu'un qui entend parfois ce rire dans sa tête et le trouve encore beau 😊` },
    { id: 'ex_g2_02', text: `"Joyeux anniversaire. Ces conversations me manquent." Pas toutes. Certaines. Celles qu'on avait. Cette façon de parler de certains sujets. Ce niveau de conversation. Cette aisance. Cette compréhension rapide. Ces échanges qui n'existent plus dans cette forme. Joyeux anniversaire, {prenom}.\nAvec pensée pour ces conversations et pour ce qui les rendait particulières, — Quelqu'un qui cherche encore ce niveau de conversation et le trouve parfois 💬` },
    { id: 'ex_g2_03', text: `"Joyeux anniversaire. Ta façon de comprendre certaines choses me manque." Cette intelligence particulière. Ces angles. Ces perspectives. Cette façon de voir certains problèmes. Qui était la tienne. Et qui n'est pas facile à trouver ailleurs. Joyeux anniversaire, {prenom}.\nAvec reconnaissance pour cette façon de comprendre et pour ce qu'elle apportait, — Quelqu'un qui appréciait ta perspective et la cherche encore parfois 🧠` },
    { id: 'ex_g2_04', text: `"Joyeux anniversaire. Avoir quelqu'un qui connaissait mes habitudes me manque." Cette connaissance. Ce confort. Cette façon d'être connu. De ne pas tout réexpliquer. D'être lu. Cette intimité des habitudes partagées. Joyeux anniversaire, {prenom}.\nAvec pensée pour ce confort de l'être connu et ce qu'il représentait, — Quelqu'un qui reconstruit ça progressivement et sait que ça prend du temps 🏠` },
    { id: 'ex_g2_05', text: `"Joyeux anniversaire. Cette complicité précise me manque." Pas la complicité en général. Celle qu'on avait. Spécifique. Qui venait de nos histoires communes. De nos références. De notre façon d'être ensemble. Cette complicité-là n'est pas remplaçable exactement. Joyeux anniversaire, {prenom}.\nAvec reconnaissance que cette complicité était particulière et irremplaçable à l'identique, — Quelqu'un qui a d'autres complicités maintenant et sait qu'elles sont différentes 🌟` },
    { id: 'ex_g2_06', text: `"Joyeux anniversaire. Les bons moments me manquent." Pas tous les moments. Les bons. Ces moments précis. Ces soirées. Ces journées. Ces instants. Qui étaient vraiment bien. Qui existaient dans leur propre réalité sans les difficultés autour. Joyeux anniversaire, {prenom}.\nAvec pensée pour ces moments précis et pour leur valeur propre, — Quelqu'un qui se souvient des bons moments sans en faire plus qu'ils n'étaient 💫` },
    { id: 'ex_g2_07', text: `"Joyeux anniversaire. Ta façon de prendre soin me manque." Cette attention particulière. Ces gestes. Ces façons de remarquer. De vérifier. De penser à quelque chose pour moi. Cette forme de soin qui était la tienne. Joyeux anniversaire, {prenom}.\nAvec reconnaissance pour cette façon de prendre soin et pour ce qu'elle représentait, — Quelqu'un qui reçoit du soin différemment maintenant et pense parfois au tien 🤲` },
    { id: 'ex_g2_08', text: `"Joyeux anniversaire. Avoir quelqu'un à appeler d'abord me manque." Cette position. Ce réflexe. Cette personne à qui on pense en premier quand quelque chose se passe. Cette place dans la hiérarchie des appels. Joyeux anniversaire, {prenom}.\nAvec honnêteté sur ce que représentait cette place dans la hiérarchie, — Quelqu'un qui a réorganisé la hiérarchie et qui y travaille encore 📞` },
    { id: 'ex_g2_09', text: `"Joyeux anniversaire. Cette sécurité particulière me manque." Cette façon de se sentir en sécurité avec quelqu'un. De pouvoir être moins parfait. Moins en représentation. Cette sécurité-là qui se construit avec le temps et la confiance. Joyeux anniversaire, {prenom}.\nAvec reconnaissance pour ce sentiment de sécurité et pour ce qu'il permettait, — Quelqu'un qui reconstruit cette sécurité progressivement 🏡` },
    { id: 'ex_g2_10', text: `"Joyeux anniversaire. Ces habitudes du quotidien me manquent." Les trucs banals. Les routines. Ces petites choses qui constituaient les jours. Qui n'avaient pas d'importance en apparence. Et dont l'absence a de l'importance. Ces manques du quotidien. Joyeux anniversaire, {prenom}.\nAvec honnêteté sur les manques du quotidien et leur nature souvent inattendue, — Quelqu'un qui a reconstruit de nouvelles habitudes et les trouve bonnes aussi 🌿` },
    { id: 'ex_g2_11', text: `"Joyeux anniversaire. Ta façon de me regarder me manque." Cette façon précise. Ce regard. Ce qu'il disait. Cette façon d'être vu par quelqu'un. D'être regardé avec une certaine qualité d'attention. Joyeux anniversaire, {prenom}.\nAvec pensée pour ce regard et pour ce qu'il représentait, — Quelqu'un qui cherche à être regardé avec cette qualité d'attention et y arrive parfois 👁️` },
    { id: 'ex_g2_12', text: `"Joyeux anniversaire. La connivence me manque." Cette chose précise. Ce regard qu'on échangeait. Ce sourire partagé sur quelque chose que les autres avaient pas vu. Cette façon d'être deux à comprendre quelque chose en même temps. Joyeux anniversaire, {prenom}.\nAvec pensée pour ces moments de connivence et pour leur valeur, — Quelqu'un qui cherche cette connivence et la trouve parfois avec d'autres 🤝` },
    { id: 'ex_g2_13', text: `"Joyeux anniversaire. Avoir quelqu'un qui connaissait mon histoire me manque." Ce contexte. Ce background. Ces choses qu'on n'a plus besoin d'expliquer. Cette économie narrative. Cette façon d'être compris sans tout remettre à plat à chaque fois. Joyeux anniversaire, {prenom}.\nAvec reconnaissance pour cette connaissance de l'histoire et ce qu'elle permettait, — Quelqu'un qui réexplique parfois son contexte et pense à ce temps gagné avec toi 📚` },
    { id: 'ex_g2_14', text: `"Joyeux anniversaire. Ce que c'était de se sentir choisi me manque." Ce sentiment. Cette façon de savoir qu'on était la personne choisie. Que parmi tout l'autre choisissait toi. Ce sentiment particulier d'être sélectionné. Joyeux anniversaire, {prenom}.\nAvec reconnaissance pour ce sentiment et pour sa valeur, — Quelqu'un qui attend d'être choisi à nouveau avec cette qualité de choix 💛` },
    { id: 'ex_g2_15', text: `"Joyeux anniversaire. Les petites attentions me manquent." Ces trucs. Ces petits gestes sans occasion. Ces pensées exprimées. Ces façons de dire que t'as pensé à moi. Ces attentions minuscules qui font une grande différence dans le quotidien. Joyeux anniversaire, {prenom}.\nAvec pensée pour ces petites attentions et pour ce qu'elles représentaient, — Quelqu'un qui apprécie les petites attentions plus depuis qu'il a vu leur absence 🌷` },
    { id: 'ex_g2_16', text: `"Joyeux anniversaire. Avoir un témoin de ma vie quotidienne me manque." Quelqu'un qui sait. Qui voit. Qui est là dans les jours normaux. Pas juste les grands moments. Le témoin du quotidien. Joyeux anniversaire, {prenom}.\nAvec reconnaissance pour ce rôle de témoin et pour sa valeur dans les jours ordinaires, — Quelqu'un qui cherche un nouveau témoin et sait ce que ça représente vraiment 👀` },
    { id: 'ex_g2_17', text: `"Joyeux anniversaire. Certaines versions de moi-même me manquent." Ces versions que j'étais avec toi. Que je suis moins maintenant. Ou différemment. Ces parts de moi qui existaient dans ce contexte. Cette identité relationnelle. Joyeux anniversaire, {prenom}.\nAvec honnêteté sur les versions de soi-même qui existent dans les relations, — Quelqu'un qui retrouve ces versions différemment maintenant et s'y retrouve 🪞` },
    { id: 'ex_g2_18', text: `"Joyeux anniversaire. Ce qui manque me dit ce que je veux." C'est ça la fonction de ce qui manque. Pas de faire souffrir. De préciser. D'informer. De dire voilà ce que tu cherches maintenant. Cette liste de manques comme carte de ce qui compte vraiment. Joyeux anniversaire, {prenom}.\nAvec gratitude pour les manques et pour ce qu'ils enseignent, — Quelqu'un qui a transformé les manques en liste de ce qu'il cherche et trouve ça utile 🗺️` },
    { id: 'ex_g2_19', text: `"Joyeux anniversaire. Je pense à toi aujourd'hui." Pas avec douleur. Pas avec regret acide. Juste cette pensée douce qui arrive certains jours. Ton anniversaire en fait partie. Il y a des dates qui portent des gens même longtemps après. La tienne porte encore quelque chose. Quelque chose de bien. Joyeux anniversaire, {prenom}.\nAvec pensée sincère et sans arrière-goût, — Quelqu'un qui pense à toi aujourd'hui et voulait que tu le saches 🌸` },
    { id: 'ex_g2_20', text: `"Joyeux anniversaire. J'espère que tu vas bien." Vraiment. Pas comme formule. Vraiment. Cette curiosité sincère pour comment ta vie se passe maintenant. Pour ce que tu traverses. Pour ce que tu construis. Pour si tu es heureux. Joyeux anniversaire, {prenom}.\nAvec sincérité totale sur cet espoir, — Quelqu'un qui veut vraiment que tu ailles bien et n'a aucune raison de mentir là-dessus 💛` },
    { id: 'ex_g2_21', text: `"Joyeux anniversaire. Je me souviens de ton premier anniversaire qu'on a fêté ensemble." Ce qu'on avait fait. Où on était. Ce que tu avais dit. Ce que j'avais préparé ou pas préparé. Ce moment qui appartenait à une période précise. Ce souvenir qui dit quelque chose sur ce qu'on était alors. Joyeux anniversaire, {prenom}.\nAvec douceur pour ce souvenir et pour la personne qu'on était à ce moment-là, — Quelqu'un qui se souvient de ce jour avec quelque chose de tendre 🎂` },
    { id: 'ex_g2_22', text: `"Joyeux anniversaire. Il y a des choses de nous que je porte encore." Pas de façon douloureuse. Des habitudes. Des façons de voir. Des trucs que tu m'as appris sans le chercher. Des références qu'on partageait. Des choses qui sont restées après que le reste soit parti. Joyeux anniversaire, {prenom}.\nAvec reconnaissance pour ce qui a persisté et pour sa valeur, — Quelqu'un qui porte encore quelques choses de toi et les trouve précieuses 🌱` },
    { id: 'ex_g2_23', text: `"Joyeux anniversaire. On a eu des moments vraiment bien." C'est vrai. Sans réécrire. Sans minimiser pour que ça fasse moins mal. Sans exagérer pour que la nostalgie soit plus belle. Des moments vraiment bien. Qui ont existé. Qui comptaient. Joyeux anniversaire, {prenom}.\nAvec honnêteté sur ce qui était bien et refus de le réécrire dans un sens ou dans l'autre, — Quelqu'un qui se souvient des bons moments tels qu'ils étaient vraiment 💫` },
    { id: 'ex_g2_24', text: `"Joyeux anniversaire. Je me souviens de comment tu riais." Cette façon spécifique. Ce son. Cette expression. Ces choses qu'on remarque des gens qu'on a aimés et qu'on ne voit plus. Ce détail qui reste dans la mémoire longtemps après que le reste s'estompe. Joyeux anniversaire, {prenom}.\nAvec tendresse pour ce souvenir précis, — Quelqu'un qui entend parfois ce rire dans sa tête et trouve ça doux 😊` },
    { id: 'ex_g2_25', text: `"Joyeux anniversaire. T'étais là pendant une période importante de ma vie." Pas par hasard. T'y étais vraiment. Présent dans cette période. Partie de comment je l'ai vécue. De ce que j'en ai retenu. De qui j'étais alors. Cette présence a compté. Elle compte encore dans la mémoire. Joyeux anniversaire, {prenom}.\nAvec reconnaissance pour cette présence pendant une période qui comptait, — Quelqu'un qui sait que cette période était meilleure parce que tu y étais 🗓️` },
    { id: 'ex_g2_26', text: `"Joyeux anniversaire. J'espère que tu as trouvé ce que tu cherchais." Pas de façon amère. Avec sincérité. Ces choses que tu voulais. Ces directions que tu prenais. Ces rêves que tu avais. J'espère que certains se sont réalisés. Que la vie a été généreuse avec toi. Joyeux anniversaire, {prenom}.\nAvec espoir sincère et désintéressé pour ce que tu cherchais, — Quelqu'un qui te souhaite de trouver sans calcul 🌟` },
    { id: 'ex_g2_27', text: `"Joyeux anniversaire. Il y a une version de moi que tu as connue que personne d'autre a connue." À cette époque. Dans ce contexte. Cette version-là. Avec ses particularités. Ses façons d'être que j'avais alors. T'es le seul ou la seule à avoir connu exactement ça. C'est étrange et précieux en même temps. Joyeux anniversaire, {prenom}.\nAvec pensée pour cette version passée et pour toi qui la connais, — Quelqu'un qui pense à cette version-là parfois et trouve ça curieux et beau 🪞` },
    { id: 'ex_g2_28', text: `"Joyeux anniversaire. La fin était juste même si c'était difficile." Pas juste facile à accepter sur le moment. Juste dans le sens de bien. De nécessaire. De ce qui devait se passer. Cette paix avec la fin. Cette compréhension que certaines choses se terminent parce qu'elles doivent. Joyeux anniversaire, {prenom}.\nAvec paix réelle sur la fin et sur ce qu'elle représentait, — Quelqu'un qui a compris la justesse de la fin et qui en est reconnaissant 🕊️` },
    { id: 'ex_g2_29', text: `"Joyeux anniversaire. Je me souviens de petites choses." Pas les grandes. Les petites. Ces détails qui n'avaient pas d'importance sur le moment. Qui en ont maintenant. La façon dont tu faisais quelque chose. Un truc que tu disais. Un geste particulier. Ces petits riens qui font la texture d'une présence. Joyeux anniversaire, {prenom}.\nAvec douceur pour ces petites choses et pour ce qu'elles représentent, — Quelqu'un dont la mémoire garde les petits détails longtemps 🌿` },
    { id: 'ex_g2_30', text: `"Joyeux anniversaire. T'as été quelqu'un d'important dans ma vie." Pas le seul. Pas pour toujours. Mais important. À ce moment-là. Dans cette période. Cette importance-là mérite d'être nommée même longtemps après. Même maintenant. Joyeux anniversaire, {prenom}.\nAvec reconnaissance simple et vraie pour cette importance, — Quelqu'un qui nomme les importances même quand le temps a passé 💛` },
    { id: 'ex_g2_31', text: `"Joyeux anniversaire. Je me demande parfois comment tu vas." Ces pensées qui arrivent sans prévenir. Ces curiosités douces. Ces moments où une chose fait penser à une autre et où ton prénom arrive dans la tête. Cette pensée pour toi qui existe encore même si on ne se voit plus. Joyeux anniversaire, {prenom}.\nAvec honnêteté sur ces pensées qui arrivent et sur leur nature douce, — Quelqu'un qui se demande parfois et n'a pas d'autre raison que la pensée elle-même 💭` },
    { id: 'ex_g2_32', text: `"Joyeux anniversaire. On s'est bien aimés à notre façon." Pas parfaitement. Pas comme dans un film. D'une façon humaine. Avec les limites et les maladresses et les bons moments et les difficiles. Cette façon-là était réelle. Elle était bien dans sa réalité imparfaite. Joyeux anniversaire, {prenom}.\nAvec paix pour la façon dont on s'est aimés, — Quelqu'un qui pense que cette façon méritait d'être nommée même maintenant 🤍` },
    { id: 'ex_g2_33', text: `"Joyeux anniversaire. Certaines choses de toi restent." Dans des habitudes. Dans des façons de voir. Dans des références. Dans des chansons qui disent quelque chose. Dans des endroits qui portent des souvenirs. Dans des expressions qu'on a gardées. Ces traces douces. Joyeux anniversaire, {prenom}.\nAvec douceur pour ces traces et pour ce qu'elles représentent, — Quelqu'un qui croise tes traces parfois et les trouve bienveillantes 🌊` },
    { id: 'ex_g2_34', text: `"Joyeux anniversaire. On aurait pu mieux se dire au revoir." Peut-être. Parfois les fins sont maladroites. Pas méchantes. Juste pas à la hauteur de ce qui avait existé. Cette pensée parfois. Qu'on aurait pu faire mieux sur la fin. Joyeux anniversaire, {prenom}.\nAvec reconnaissance douce de cette maladresse partagée, — Quelqu'un qui pense parfois que la fin méritait mieux et l'accepte quand même 🌙` },
    { id: 'ex_g2_35', text: `"Joyeux anniversaire. Je te souhaite exactement ce que tu mérites." Et tu mérites des bonnes choses. Ça c'est vrai même longtemps après. Même sans contact. Même avec tout ce qui s'est passé. Cette conviction que tu mérites du bien reste. Joyeux anniversaire, {prenom}.\nAvec sincérité totale sur ce souhait, — Quelqu'un qui te souhaite du bien sans condition ni calcul 🌟` },
    { id: 'ex_g2_36', text: `"Joyeux anniversaire. Cette période avec toi m'a appris quelque chose." Pas toujours agréablement. Pas toujours de façon évidente. Mais quelque chose. Sur moi. Sur ce que je voulais. Sur comment fonctionner avec quelqu'un. Ces leçons tirées de ce qu'on a été ensemble. Joyeux anniversaire, {prenom}.\nAvec gratitude pour les leçons même quand elles venaient par des chemins difficiles, — Quelqu'un qui a appris et qui pense que c'était nécessaire 📚` },
    { id: 'ex_g2_37', text: `"Joyeux anniversaire. Je suis content que tu aies existé dans ma vie." Pas juste tolérant de cette existence. Content. Cette présence a contribué à quelque chose. À qui je suis. À ce que j'ai vécu. À des moments qui ont compté. Joyeux anniversaire, {prenom}.\nAvec gratitude simple et vraie pour cette existence dans ma vie, — Quelqu'un qui est sincèrement content que ça ait existé 💛` },
    { id: 'ex_g2_38', text: `"Joyeux anniversaire. Il y a une gentillesse dans le fait de te le souhaiter." Ce message. Ce geste simple. Ce joyeux anniversaire envoyé malgré le temps et la distance et tout ce qui s'est passé. Cette gentillesse-là dit quelque chose. Sur ce que c'était. Sur ce que ça reste. Joyeux anniversaire, {prenom}.\nAvec conscience de ce que ce message représente et envie de le faire quand même, — Quelqu'un qui a choisi la gentillesse aujourd'hui et qui en est content ❤️` },
    { id: 'ex_g2_39', text: `"Joyeux anniversaire. La connaissance du corps de quelqu'un me manque." Cette intimité physique. Cette façon de connaître comment quelqu'un bouge. Respire. Se tient. Cette topographie humaine. Cette connaissance intime. Joyeux anniversaire, {prenom}.\nAvec douceur pour cette forme d'intimité et pour ce qu'elle représentait, — Quelqu'un qui sait que cette connaissance se reconstruit et est patient avec ça 🌸` },
  ],
};

